// ============================================
// SCORING DE COMPLÉTUDE - n8n Code Node
// ============================================
// Objectif : Évaluer la qualité des données entrantes pour router
//            intelligemment vers les nœuds Match appropriés
//
// Sortie : Score 0-100 + Tier (EXCELLENT/GOOD/MEDIUM/POOR/MINIMAL)
// ============================================

const items = $input.all();

// ============================================
// HELPERS
// ============================================

/**
 * Récupère une valeur de manière robuste
 */
function get(obj, ...keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
}

/**
 * Normalise un texte pour analyse
 */
function normalize(text) {
  if (!text) return "";
  return String(text)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
}

/**
 * Compte le nombre de mots significatifs (≥3 caractères)
 */
function countSignificantWords(text) {
  if (!text) return 0;
  const words = normalize(text).split(/\s+/);
  return words.filter(w => w.length >= 3).length;
}

/**
 * Vérifie si une valeur est présente et non vide
 */
function isPresent(value) {
  return value !== undefined && value !== null && String(value).trim() !== "";
}

/**
 * Extrait u_moto_brand depuis href
 */
function extractBrandFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_brand:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(m[1].replace(/\+/g, " "));
  } catch (e) {
    return m[1].replace(/\+/g, " ");
  }
}

/**
 * Extrait u_moto_model depuis href
 */
function extractModelFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_model:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(m[1].replace(/\+/g, " "));
  } catch (e) {
    return m[1].replace(/\+/g, " ");
  }
}

/**
 * Extrait cubic_capacity depuis href
 */
function extractCCFromHref(href) {
  const h = String(href || "");
  const m = h.match(/cubic_capacity:(\d{2,4})/i);
  return m ? parseInt(m[1], 10) : 0;
}

/**
 * Parse année depuis texte (format MM/YYYY ou YYYY)
 */
function parseYear(text) {
  const str = String(text || "").trim();
  if (!str) return 0;

  // MM/YYYY
  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return parseInt(mmyyyy[2], 10);

  // YYYY
  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return parseInt(yyyy[0], 10);

  return 0;
}

// ============================================
// SCORING DE COMPLÉTUDE
// ============================================

/**
 * Calcule le score de complétude d'une annonce
 * Retourne un objet avec score (0-100) et détails
 */
function calculateCompletudeScore(item) {
  let score = 0;
  const details = {};

  // ────────────────────────────────────────────────────────
  // 1. MARQUE (25 points max)
  // ────────────────────────────────────────────────────────
  const brandField = get(item, "text-body-1 (2)", "annonce_brand_input", "Marque_scrap");
  const brandHref = get(item, "text-body-1 href (2)", "text-body-1 href");
  const brandFromHref = extractBrandFromHref(brandHref);

  if (brandFromHref) {
    // Marque depuis href LBC (le plus fiable)
    score += 25;
    details.brand_source = "href";
    details.brand_quality = "EXCELLENT";
  } else if (brandField) {
    // Marque depuis champ scraped
    score += 20;
    details.brand_source = "field";
    details.brand_quality = "GOOD";
  } else {
    details.brand_source = "missing";
    details.brand_quality = "NONE";
  }

  // ────────────────────────────────────────────────────────
  // 2. MODÈLE (20 points max)
  // ────────────────────────────────────────────────────────
  const modelHref = get(item, "text-body-1 href (3)");
  const modelFromHref = extractModelFromHref(modelHref);
  const modelField = get(item, "text-body-1 (3)");
  const versionField = get(item, "text-body-1 (8)"); // Version constructeur

  const modelNorm = normalize(modelFromHref);
  const isModelAutre = modelNorm === "autre" || modelNorm.includes(" autre");

  if (modelFromHref && !isModelAutre) {
    // Modèle depuis href LBC (non "autre")
    score += 20;
    details.model_source = "href";
    details.model_quality = "EXCELLENT";
  } else if (versionField && countSignificantWords(versionField) >= 2) {
    // Version constructeur riche (ex: "1050_Speed Triple 1050 ABS")
    score += 18;
    details.model_source = "version_field";
    details.model_quality = "VERY_GOOD";
  } else if (modelField) {
    // Champ modèle présent
    score += 12;
    details.model_source = "field";
    details.model_quality = "GOOD";
  } else if (versionField) {
    // Version constructeur pauvre
    score += 8;
    details.model_source = "version_field_weak";
    details.model_quality = "MEDIUM";
  } else {
    details.model_source = "missing";
    details.model_quality = "NONE";
  }

  // ────────────────────────────────────────────────────────
  // 3. CYLINDRÉE CC (15 points max)
  // ────────────────────────────────────────────────────────
  const ccHref = get(item, "text-body-1 href (5)");
  const ccFromHref = extractCCFromHref(ccHref);
  const ccField1 = get(item, "text-body-1 (7)");
  const ccField2 = get(item, "text-body-1 (13)", "vehicule_cc_txt", "CC", "cc");

  if (ccFromHref) {
    // CC depuis href LBC (le plus fiable)
    score += 15;
    details.cc_source = "href";
    details.cc_quality = "EXCELLENT";
  } else if (ccField1) {
    // Champ CC dédié (7)
    score += 12;
    details.cc_source = "field_primary";
    details.cc_quality = "GOOD";
  } else if (ccField2) {
    // Champ CC secondaire (13)
    score += 10;
    details.cc_source = "field_secondary";
    details.cc_quality = "MEDIUM";
  } else {
    details.cc_source = "missing";
    details.cc_quality = "NONE";
  }

  // ────────────────────────────────────────────────────────
  // 4. ANNÉE (10 points max)
  // ────────────────────────────────────────────────────────
  const year1 = get(item, "text-body-1 (4)", "Annee_du_modele");
  const year2 = get(item, "text-body-1 (9)", "Mise_en_circulation");

  const yearParsed1 = parseYear(year1);
  const yearParsed2 = parseYear(year2);

  if (yearParsed1 || yearParsed2) {
    score += 10;
    details.year_source = yearParsed1 ? "field_primary" : "field_secondary";
    details.year_quality = "GOOD";
  } else {
    details.year_source = "missing";
    details.year_quality = "NONE";
  }

  // ────────────────────────────────────────────────────────
  // 5. DESCRIPTION (15 points max)
  // ────────────────────────────────────────────────────────
  const desc = get(
    item,
    "annonce_description",
    "text-body-1 (16)",
    "text-body-1 (14)",
    "Description_complete",
    "description"
  );

  const descWordCount = countSignificantWords(desc);

  if (descWordCount >= 50) {
    // Description très complète (≥50 mots)
    score += 15;
    details.description_length = descWordCount;
    details.description_quality = "EXCELLENT";
  } else if (descWordCount >= 20) {
    // Description complète (20-49 mots)
    score += 12;
    details.description_length = descWordCount;
    details.description_quality = "GOOD";
  } else if (descWordCount >= 10) {
    // Description moyenne (10-19 mots)
    score += 8;
    details.description_length = descWordCount;
    details.description_quality = "MEDIUM";
  } else if (descWordCount >= 5) {
    // Description pauvre (5-9 mots)
    score += 4;
    details.description_length = descWordCount;
    details.description_quality = "POOR";
  } else {
    details.description_length = descWordCount;
    details.description_quality = "NONE";
  }

  // ────────────────────────────────────────────────────────
  // 6. PHOTOS (5 points max)
  // ────────────────────────────────────────────────────────
  const photo1 = get(item, "size-full src", "Photo_1");
  const photo2 = get(item, "size-full src (2)", "Photo_2");
  const photo3 = get(item, "size-full src (3)", "Photo_3");

  const photoCount = [photo1, photo2, photo3].filter(p => isPresent(p)).length;

  if (photoCount >= 3) {
    score += 5;
    details.photo_count = photoCount;
    details.photo_quality = "EXCELLENT";
  } else if (photoCount === 2) {
    score += 4;
    details.photo_count = photoCount;
    details.photo_quality = "GOOD";
  } else if (photoCount === 1) {
    score += 2;
    details.photo_count = photoCount;
    details.photo_quality = "MEDIUM";
  } else {
    details.photo_count = 0;
    details.photo_quality = "NONE";
  }

  // ────────────────────────────────────────────────────────
  // 7. TITRE (10 points max)
  // ────────────────────────────────────────────────────────
  const title = get(
    item,
    "text-body-1 (8)",
    "text-headline-1-expanded",
    "annonce_title",
    "relative"
  );

  const titleWordCount = countSignificantWords(title);

  if (titleWordCount >= 5) {
    // Titre riche (≥5 mots significatifs)
    score += 10;
    details.title_length = titleWordCount;
    details.title_quality = "EXCELLENT";
  } else if (titleWordCount >= 3) {
    // Titre moyen (3-4 mots)
    score += 7;
    details.title_length = titleWordCount;
    details.title_quality = "GOOD";
  } else if (titleWordCount >= 1) {
    // Titre pauvre (1-2 mots)
    score += 3;
    details.title_length = titleWordCount;
    details.title_quality = "POOR";
  } else {
    details.title_length = 0;
    details.title_quality = "NONE";
  }

  // ────────────────────────────────────────────────────────
  // TOTAL : 100 points max
  // ────────────────────────────────────────────────────────
  details.total_score = score;

  return { score, details };
}

/**
 * Détermine le tier de qualité basé sur le score
 */
function determineTier(score) {
  if (score >= 80) return "EXCELLENT";
  if (score >= 60) return "GOOD";
  if (score >= 40) return "MEDIUM";
  if (score >= 20) return "POOR";
  return "MINIMAL";
}

/**
 * Détermine le nœud Match recommandé
 */
function determineRecommendedMatch(score, tier) {
  if (tier === "EXCELLENT") return "1st Match";
  if (tier === "GOOD") return "2nd Match";
  if (tier === "MEDIUM") return "3rd Match";
  if (tier === "POOR") return "4th Match";
  return "5th Match";
}

/**
 * Calcule un flag de priorité pour le routing
 */
function calculatePriority(score, details) {
  // Priorité haute si :
  // - Score ≥ 70
  // - ET marque + modèle href présents
  // - ET CC href présent

  const hasExcellentData =
    score >= 70 &&
    details.brand_quality === "EXCELLENT" &&
    details.model_quality === "EXCELLENT" &&
    details.cc_quality === "EXCELLENT";

  if (hasExcellentData) return "HIGH";

  // Priorité moyenne si :
  // - Score ≥ 50
  // - ET au moins marque + (modèle OU cc)

  const hasGoodData =
    score >= 50 &&
    details.brand_quality !== "NONE" &&
    (details.model_quality !== "NONE" || details.cc_quality !== "NONE");

  if (hasGoodData) return "MEDIUM";

  // Sinon priorité basse
  return "LOW";
}

// ============================================
// TRAITEMENT
// ============================================

const results = items.map(inputItem => {
  const item = inputItem.json;

  // Calculer le score de complétude
  const { score, details } = calculateCompletudeScore(item);

  // Déterminer le tier
  const tier = determineTier(score);

  // Recommandation de routing
  const recommendedMatch = determineRecommendedMatch(score, tier);

  // Priorité
  const priority = calculatePriority(score, details);

  // Déterminer si review manuelle recommandée
  const needsManualReview = score < 30 || tier === "MINIMAL";

  // Flags de complétude par catégorie
  const completenessFlags = {
    has_brand: details.brand_quality !== "NONE",
    has_model: details.model_quality !== "NONE",
    has_cc: details.cc_quality !== "NONE",
    has_year: details.year_quality !== "NONE",
    has_description: details.description_quality !== "NONE",
    has_photos: details.photo_quality !== "NONE",
    has_title: details.title_quality !== "NONE"
  };

  // Compter le nombre de champs présents
  const fieldsPresent = Object.values(completenessFlags).filter(Boolean).length;
  const fieldsTotal = Object.keys(completenessFlags).length;
  const completenessPercentage = Math.round((fieldsPresent / fieldsTotal) * 100);

  return {
    json: {
      // ========================================
      // DONNÉES ORIGINALES (préservées)
      // ========================================
      ...item,

      // ========================================
      // SCORING DE COMPLÉTUDE (nouveaux champs)
      // ========================================
      data_quality_score: score,
      data_quality_tier: tier,
      data_quality_priority: priority,

      recommended_match_node: recommendedMatch,
      needs_manual_review: needsManualReview,

      completeness_percentage: completenessPercentage,
      fields_present: fieldsPresent,
      fields_total: fieldsTotal,

      // ========================================
      // DÉTAILS DE SCORING (pour debug)
      // ========================================
      _completude_details: {
        brand: {
          source: details.brand_source,
          quality: details.brand_quality,
          points: details.brand_quality === "EXCELLENT" ? 25 :
                  details.brand_quality === "GOOD" ? 20 : 0
        },
        model: {
          source: details.model_source,
          quality: details.model_quality,
          points: details.model_quality === "EXCELLENT" ? 20 :
                  details.model_quality === "VERY_GOOD" ? 18 :
                  details.model_quality === "GOOD" ? 12 :
                  details.model_quality === "MEDIUM" ? 8 : 0
        },
        cc: {
          source: details.cc_source,
          quality: details.cc_quality,
          points: details.cc_quality === "EXCELLENT" ? 15 :
                  details.cc_quality === "GOOD" ? 12 :
                  details.cc_quality === "MEDIUM" ? 10 : 0
        },
        year: {
          source: details.year_source,
          quality: details.year_quality,
          points: details.year_quality === "GOOD" ? 10 : 0
        },
        description: {
          length: details.description_length,
          quality: details.description_quality,
          points: details.description_quality === "EXCELLENT" ? 15 :
                  details.description_quality === "GOOD" ? 12 :
                  details.description_quality === "MEDIUM" ? 8 :
                  details.description_quality === "POOR" ? 4 : 0
        },
        photos: {
          count: details.photo_count,
          quality: details.photo_quality,
          points: details.photo_quality === "EXCELLENT" ? 5 :
                  details.photo_quality === "GOOD" ? 4 :
                  details.photo_quality === "MEDIUM" ? 2 : 0
        },
        title: {
          length: details.title_length,
          quality: details.title_quality,
          points: details.title_quality === "EXCELLENT" ? 10 :
                  details.title_quality === "GOOD" ? 7 :
                  details.title_quality === "POOR" ? 3 : 0
        }
      },

      // ========================================
      // FLAGS DE COMPLÉTUDE
      // ========================================
      _completeness_flags: completenessFlags
    }
  };
});

// ============================================
// STATS GLOBALES (pour monitoring)
// ============================================
const stats = {
  total_items: results.length,
  distribution: {
    EXCELLENT: results.filter(r => r.json.data_quality_tier === "EXCELLENT").length,
    GOOD: results.filter(r => r.json.data_quality_tier === "GOOD").length,
    MEDIUM: results.filter(r => r.json.data_quality_tier === "MEDIUM").length,
    POOR: results.filter(r => r.json.data_quality_tier === "POOR").length,
    MINIMAL: results.filter(r => r.json.data_quality_tier === "MINIMAL").length
  },
  average_score: Math.round(
    results.reduce((sum, r) => sum + r.json.data_quality_score, 0) / results.length
  ),
  manual_review_needed: results.filter(r => r.json.needs_manual_review).length
};

console.log("📊 SCORING DE COMPLÉTUDE - STATS:");
console.log(`   Total items: ${stats.total_items}`);
console.log(`   Score moyen: ${stats.average_score}/100`);
console.log(`   Distribution:`);
console.log(`     - EXCELLENT: ${stats.distribution.EXCELLENT} (${Math.round(stats.distribution.EXCELLENT / stats.total_items * 100)}%)`);
console.log(`     - GOOD: ${stats.distribution.GOOD} (${Math.round(stats.distribution.GOOD / stats.total_items * 100)}%)`);
console.log(`     - MEDIUM: ${stats.distribution.MEDIUM} (${Math.round(stats.distribution.MEDIUM / stats.total_items * 100)}%)`);
console.log(`     - POOR: ${stats.distribution.POOR} (${Math.round(stats.distribution.POOR / stats.total_items * 100)}%)`);
console.log(`     - MINIMAL: ${stats.distribution.MINIMAL} (${Math.round(stats.distribution.MINIMAL / stats.total_items * 100)}%)`);
console.log(`   Review manuelle nécessaire: ${stats.manual_review_needed}`);

return results;

// =====================================================
// 1ST MATCH - STRICT (données EXCELLENT)
// =====================================================
// Objectif : Matcher les annonces avec données excellentes (score 80-100%)
//
// Stratégie :
// - Seuils stricts (MIN_COV_ALPHA = 0.85, MIN_ACCEPT = 0.78)
// - Priorité href LBC (données normalisées)
// - Gates stricts (CC ≤ 80cc, année dans range)
// - Scoring composite classique
// - 2 passes (avec/sans gate année)
//
// Entrée attendue : Annonces tier "EXCELLENT" (data_quality_score 80-100%)
// Sortie : Annonces matchées avec confiance HIGH majoritaire
// =====================================================

const allItems = $input.all().map(i => i.json);

// =====================================================
// HELPERS GÉNÉRIQUES
// =====================================================

function get(obj, ...keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
}

function pick(obj, keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
}

// =====================================================
// NORMALISATION & TOKENIZATION
// =====================================================

const STOP_WORDS = new Set([
  "moto", "motos", "scooter", "roadster", "trail", "enduro", "cross",
  "vend", "vente", "vends", "urgent", "etat", "tres", "super", "parfait",
  "paiement", "securise", "option", "full", "abs", "a2", "ct", "ok",
  "km", "kms", "kilometrage", "boite", "vitesse", "manuelle",
  "prix", "euro", "eur", "garantie", "factures", "entretien"
]);

function normalize(text) {
  if (!text) return "";
  let s = String(text)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();

  s = s.replace(/_/g, " ");
  s = s.replace(/[/|]/g, " ");
  s = s.replace(/[^a-z0-9]+/g, " ");
  s = s.replace(/\s+/g, " ").trim();

  // Normalisation modèles courants
  s = s.replace(/\b(mt)\s*0?(\d{2})\b/g, "$1$2");
  s = s.replace(/\b(fz)\s*(\d)\b/g, "$1$2");
  s = s.replace(/\b(gs)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(r)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(v\s*strom)\b/g, "vstrom");
  s = s.replace(/\b(dr)\s*z\b/g, "drz");

  return s;
}

function brandKey(brand) {
  return normalize(brand).replace(/\s+/g, "");
}

function tokenize(text) {
  const n = normalize(text);
  if (!n) return [];

  const tokens = n.split(" ").filter(t => {
    if (!t) return false;
    if (STOP_WORDS.has(t)) return false;
    if (/^\d+$/.test(t)) return true; // garde les nombres
    return t.length >= 2;
  });

  return tokens;
}

function tokensAlphaOnly(tokens) {
  return tokens.filter(t => /[a-z]/.test(t) && t.length >= 2);
}

function isNumberToken(t) {
  return /^\d+$/.test(t);
}

// =====================================================
// EXTRACTION DONNÉES ANNONCE
// =====================================================

const getAnnonceTitle = (a) =>
  get(a, "text-body-1 (8)", "text-headline-1-expanded", "annonce_title", "relative");

const getAnnonceDesc = (a) =>
  get(a, "annonce_description", "text-body-1 (16)", "text-body-1 (14)", "Description_complete");

const getAnnonceUrl = (a) =>
  get(a, "absolute href", "Url_Https", "annonce_url", "relative");

const getAnnonceBrand = (a) =>
  get(a, "text-body-1 (2)", "annonce_brand_input", "Marque_scrap");

const getAnnonceYearRaw1 = (a) =>
  get(a, "text-body-1 (4)", "Annee_du_modele", "annonce_year_input_1");

const getAnnonceYearRaw2 = (a) =>
  get(a, "text-body-1 (9)", "Mise_en_circulation", "annonce_year_input_2");

const getAnnonceCCHref = (a) => get(a, "text-body-1 href (5)");
const getAnnonceModelHref = (a) => get(a, "text-body-1 href (3)");
const getAnnonceBrandHref = (a) => get(a, "text-body-1 href (2)", "text-body-1 href");

// =====================================================
// EXTRACTION DONNÉES MODÈLE
// =====================================================

const getModeleField = (m) => pick(m, ["Modèle", "Modele", "modele", "Model", "MODELE"]) || "";
const getMarqueField = (m) => pick(m, ["Marque", "marque", "MARQUE", "Brand", "brand"]) || "";
const getYearStartField = (m) => pick(m, ["Année début", "Annee debut", "Year start"]) || "";
const getYearEndField = (m) => pick(m, ["Année fin", "Annee fin", "Year end"]) || "";

// =====================================================
// PARSING ANNÉE
// =====================================================

function parseYearMonth(s) {
  const str = String(s || "").trim();
  if (!str) return { year: 0, month: 0 };

  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return { month: parseInt(mmyyyy[1], 10), year: parseInt(mmyyyy[2], 10) };

  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return { month: 0, year: parseInt(yyyy[0], 10) };

  return { year: 0, month: 0 };
}

function pickAnnonceYear(a, adText) {
  const d1 = parseYearMonth(getAnnonceYearRaw1(a));
  if (d1.year) return d1.year;

  const d2 = parseYearMonth(getAnnonceYearRaw2(a));
  if (d2.year) return d2.year;

  // Fallback : extraction depuis texte
  const m = String(adText || "").match(/\b(19|20)\d{2}\b/);
  if (m) return parseInt(m[0], 10);

  return 0;
}

// =====================================================
// EXTRACTION CC
// =====================================================

function ccFromHref(href) {
  const s = String(href || "");
  const m = s.match(/cubic_capacity:(\d{2,4})/i);
  return m ? parseInt(m[1], 10) : 0;
}

function extractCCFromText(text) {
  const raw = String(text || "");
  if (!raw.trim()) return 0;

  const noKm = raw.replace(/\b(\d{1,6})\s*km\b/gi, " ");
  const s = normalize(noKm);

  let m = s.match(/\b(\d{2,4})\s*(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  m = s.match(/\b(\d{2,4})(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  return 0;
}

function extractNumbers(text) {
  const raw = String(text || "")
    .replace(/\b(\d{1,6})\s*km\b/gi, " ")
    .replace(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/g, " ");
  const s = normalize(raw);
  return (s.match(/\b\d{3,4}\b/g) || []).map(n => parseInt(n, 10));
}

function inferCCFromNumbers(adText, annonceYear) {
  const nums = extractNumbers(adText);
  const candidates = nums.filter(n =>
    n >= 50 && n <= 2500 && (!annonceYear || n !== annonceYear)
  );
  if (!candidates.length) return 0;
  return Math.max(...candidates);
}

function getAnnonceCC(a, adText, annonceYear) {
  // Priorité 1 : href LBC (le plus fiable pour 1st Match)
  const ccH = ccFromHref(getAnnonceCCHref(a));
  if (ccH) return ccH;

  // Priorité 2 : champ texte
  const ccTxt = get(a, "text-body-1 (7)", "vehicule_cc_txt", "CC", "cc");
  const ccField = extractCCFromText(ccTxt);
  if (ccField) return ccField;

  // Priorité 3 : extraction depuis description
  const ccT = extractCCFromText(adText);
  if (ccT) return ccT;

  // Priorité 4 : inférence depuis nombres
  const ccN = inferCCFromNumbers(adText, annonceYear || 0);
  if (ccN) return ccN;

  return 0;
}

// =====================================================
// EXTRACTION BRAND/MODEL DEPUIS HREF
// =====================================================

function decodePlus(s) {
  return String(s || "").replace(/\+/g, " ");
}

function extractBrandFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_brand:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

function extractModelFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_model:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

// =====================================================
// SIMILARITÉ
// =====================================================

function jaccard(aTokens, bTokens) {
  if (!aTokens.length || !bTokens.length) return 0;
  const A = new Set(aTokens);
  const B = new Set(bTokens);
  let inter = 0;
  for (const x of A) if (B.has(x)) inter++;
  const union = A.size + B.size - inter;
  return union ? inter / union : 0;
}

function coverageSet(adSet, modelTokens) {
  if (!modelTokens.length) return 0;
  let hit = 0;
  for (const t of modelTokens) if (adSet.has(t)) hit++;
  return hit / modelTokens.length;
}

// =====================================================
// VARIANTS & DOMINANTS
// =====================================================

function modelVariants(modelRaw) {
  const cleaned = String(modelRaw || "").replace(/[|]/g, "/");
  const parts = cleaned.split("/").map(p => p.trim()).filter(Boolean);
  return Array.from(new Set(parts.map(p => normalize(p)).filter(Boolean)));
}

function getModelDominantTokens(modelRaw) {
  const n = normalize(modelRaw);
  const nums = n.match(/\b\d{3,4}\b/g) || [];
  if (nums.length) return nums.map(Number);

  const toks = tokenize(modelRaw);
  return toks.filter(t => /\d/.test(t) || t.length >= 4);
}

// =====================================================
// SÉPARATION MODÈLES / ANNONCES
// =====================================================

const modeles = [];
const annonces = [];

for (const item of allItems) {
  const isModele =
    !!getMarqueField(item) &&
    !!getModeleField(item) &&
    get(item, "Cylindrée (cc)", "Type (M/S/E)", "Type(M/S/E)") !== "";

  const isAnnonce =
    get(item, "text-body-1 (8)", "text-headline-1-expanded", "relative",
        "absolute href", "Url_Https", "annonce_url") !== "";

  if (isModele) modeles.push(item);
  else if (isAnnonce) annonces.push(item);
}

if (!modeles.length) {
  return annonces.map(a => ({
    json: {
      ...a,
      matching_engine: "1ST_MATCH_NO_MODELS",
      matched_score: 0,
      matched_confidence: "NONE",
      needs_review: true
    }
  }));
}

// =====================================================
// INDEX MARQUES
// =====================================================

const brandIndex = new Map();

for (const m of modeles) {
  const brandRaw = getMarqueField(m);
  const modelRaw = getModeleField(m);

  const bKey = brandKey(brandRaw);
  if (!bKey) continue;

  const variants = modelVariants(modelRaw);
  if (!variants.length) continue;

  const ys = parseInt(getYearStartField(m) || 0, 10) || 0;
  let ye = getYearEndField(m);
  ye = (ye === null || ye === undefined || ye === "") ? 9999 : (parseInt(ye, 10) || 9999);

  const cc = Math.round(Number(get(m, "Cylindrée (cc)") || 0)) || 0;

  const variantAlphaTokens = variants
    .map(v => tokensAlphaOnly(tokenize(v)))
    .filter(t => t.length);

  if (!variantAlphaTokens.length) continue;

  const doms = getModelDominantTokens(modelRaw);
  const modelNoSpace = normalize(modelRaw).replace(/\s+/g, "");

  const prepared = {
    raw: m,
    brandRaw,
    bKey,
    ys,
    ye,
    cc,
    variants,
    variantAlphaTokens,
    combinedTok: tokenize(`${brandRaw} ${modelRaw}`),
    dominants: doms,
    modelNoSpace
  };

  if (!brandIndex.has(bKey)) brandIndex.set(bKey, []);
  brandIndex.get(bKey).push(prepared);
}

const knownBrandKeys = Array.from(brandIndex.keys()).sort((a, b) => b.length - a.length);

// =====================================================
// PARAMÈTRES 1ST MATCH (STRICT)
// =====================================================

const MIN_COV_ALPHA = 0.85;    // 85% couverture alpha (strict)
const MIN_ACCEPT = 0.78;        // 78% score minimum (strict)
const CC_BLOCK_DIFF = 80;       // 80cc tolérance (strict)

// =====================================================
// SCORING COMPOSITE CLASSIQUE
// =====================================================

function computeClassicScore(adTok, adSet, p, annonceCC, annonceYear) {
  // 1. Coverage alpha (70%)
  let bestCov = 0;
  for (const vat of p.variantAlphaTokens) {
    const cov = coverageSet(adSet, vat);
    if (cov > bestCov) bestCov = cov;
  }

  // 2. Jaccard (20%)
  const jac = jaccard(adTok, p.combinedTok);

  // 3. CC exact (5%)
  let ccBonus = 0;
  if (annonceCC && p.cc) {
    if (annonceCC === p.cc) {
      ccBonus = 1.0;
    }
  }

  // 4. Year exact (5%)
  let yearBonus = 0;
  if (annonceYear && p.ys && p.ye) {
    if (annonceYear >= p.ys && annonceYear <= p.ye) {
      yearBonus = 1.0;
    }
  }

  // Score composite
  const score = (
    bestCov * 0.70 +
    jac * 0.20 +
    ccBonus * 0.05 +
    yearBonus * 0.05
  );

  return { score, bestCov, jac, ccBonus, yearBonus };
}

// =====================================================
// MATCHING
// =====================================================

const results = [];

for (const a of annonces) {
  const title = getAnnonceTitle(a);
  const desc = getAnnonceDesc(a);
  const url = getAnnonceUrl(a);

  const hrefModel = getAnnonceModelHref(a) || "";
  const hrefCC = getAnnonceCCHref(a) || "";
  const hrefBrand = getAnnonceBrandHref(a) || "";

  // Priorité href pour 1st Match
  const brandFromHrefRaw = extractBrandFromHref(hrefBrand);
  const brandFromFieldRaw = getAnnonceBrand(a);

  const brandFromHrefKey = brandKey(brandFromHrefRaw);
  const brandFromFieldKey = brandKey(brandFromFieldRaw);

  const adTextBase = `${title} ${desc}`.trim();

  // Marque : priorité href
  let brandAnnonceKey = brandFromHrefKey || brandFromFieldKey;

  // Model hint depuis href (priorité)
  let modelHint = extractModelFromHref(hrefModel);
  const modelNorm = normalize(modelHint);
  const isModelAutre = modelNorm === "autre" || modelNorm.includes(" autre");

  if (!modelHint || isModelAutre) {
    // Fallback sur field
    modelHint = get(a, "text-body-1 (8)", "text-body-1 (3)");
  }

  const adTextUsed = modelHint ? `${adTextBase} ${modelHint}`.trim() : adTextBase;

  const annonceYear = pickAnnonceYear(a, adTextUsed);
  const annonceCC = getAnnonceCC(a, adTextUsed, annonceYear);

  // Vérifier si marque trouvée
  if (!brandAnnonceKey || !brandIndex.has(brandAnnonceKey)) {
    results.push({
      json: {
        ...a,
        annonce_title: title,
        annonce_url: url,
        annonce_year_resolved: annonceYear || "",
        annonce_cc_resolved: annonceCC || "",

        matched_ok: false,
        matched_marque: "",
        matched_modele: modelHint || "",
        matched_score: 0,
        matched_confidence: "NONE",
        matching_engine: "1ST_MATCH_NO_BRAND",
        needs_review: true,
        reason_no_match: "brand_not_found"
      }
    });
    continue;
  }

  const adTok = tokenize(adTextUsed);
  const adSet = new Set(adTok);
  const adNumbers = extractNumbers(adTextUsed);

  const baseCandidates = brandIndex.get(brandAnnonceKey) || [];

  // Passes : Pass 1 avec année, Pass 2 sans année
  const passes = [{ useYear: true }, { useYear: false }];

  let bestPrepared = null;
  let bestScore = 0;
  let bestDetails = null;
  let usedYearFilter = false;

  for (const pass of passes) {
    let foundInPass = false;

    for (const p of baseCandidates) {
      // Gate année (strict en pass 1)
      if (pass.useYear && annonceYear) {
        if (annonceYear < p.ys || annonceYear > p.ye) continue;
      }

      // Gate CC strict (≤ 80cc)
      if (annonceCC && p.cc) {
        const diff = Math.abs(p.cc - annonceCC);
        if (diff > CC_BLOCK_DIFF) continue;
      }

      // Gate dominants (upgrade prevention)
      if (p.dominants.length > 0) {
        const hasCommonDom = p.dominants.some(d => adNumbers.includes(d));
        if (!hasCommonDom) continue;
      }

      // Scoring
      const { score, bestCov, jac, ccBonus, yearBonus } =
        computeClassicScore(adTok, adSet, p, annonceCC, annonceYear);

      // Gate coverage minimum
      if (bestCov < MIN_COV_ALPHA) continue;

      if (score > bestScore) {
        bestScore = score;
        bestPrepared = p;
        bestDetails = { bestCov, jac, ccBonus, yearBonus };
        usedYearFilter = pass.useYear && !!annonceYear;
        foundInPass = true;
      }
    }

    // Si trouvé en pass 1, ne pas faire pass 2
    if (pass.useYear && foundInPass) break;
  }

  const accept = !!bestPrepared && bestScore >= MIN_ACCEPT;
  const best = accept ? bestPrepared.raw : null;

  // Déterminer la confiance
  let confidence = "NONE";
  if (accept) {
    if (bestScore >= 0.85) confidence = "HIGH";
    else confidence = "MEDIUM";
  }

  results.push({
    json: {
      ...a,
      annonce_title: title,
      annonce_url: url,
      annonce_year_resolved: annonceYear || "",
      used_year_filter: usedYearFilter,
      annonce_cc_resolved: annonceCC || "",

      matched_ok: accept,
      matched_marque: accept ? (getMarqueField(best) || "") : "",
      matched_modele: accept ? (getModeleField(best) || "") : (modelHint || ""),
      matched_generations: accept ? (get(best, "Spéc/Génération", "Spec/Generation") || "") : "",
      matched_coloris: accept ? (get(best, "Coloris commercial") || "") : "",
      matched_annee_debut: accept ? (getYearStartField(best) || "") : "",
      matched_annee_fin: accept ? (getYearEndField(best) || "") : "",
      matched_cylindree: accept ? (get(best, "Cylindrée (cc)") || "") : "",

      matched_score: accept ? Number(bestScore.toFixed(3)) : 0,
      matched_confidence: confidence,
      matched_quality: accept ? "auto_match_1st" : "no_match",
      matching_engine: "1ST_MATCH_STRICT_V1",
      needs_review: !accept || confidence === "MEDIUM",
      reason_no_match: accept ? "" : "below_threshold_or_filtered",

      // Détails pour debug
      _match_debug: {
        brandKey: brandAnnonceKey,
        modelHint,
        adTokensCount: adTok.length,
        coverageAlpha: accept ? Number(bestDetails.bestCov.toFixed(3)) : 0,
        jaccard: accept ? Number(bestDetails.jac.toFixed(3)) : 0,
        ccBonus: accept ? Number(bestDetails.ccBonus.toFixed(2)) : 0,
        yearBonus: accept ? Number(bestDetails.yearBonus.toFixed(2)) : 0,
        minCovAlpha: MIN_COV_ALPHA,
        minAccept: MIN_ACCEPT,
        ccBlockDiff: CC_BLOCK_DIFF
      }
    }
  });
}

// =====================================================
// STATS
// =====================================================

const stats = {
  total: results.length,
  matched: results.filter(r => r.json.matched_ok).length,
  confidence_high: results.filter(r => r.json.matched_confidence === "HIGH").length,
  confidence_medium: results.filter(r => r.json.matched_confidence === "MEDIUM").length,
  needs_review: results.filter(r => r.json.needs_review).length
};

console.log("🥇 1ST MATCH (STRICT) - STATS:");
console.log(`   Total items: ${stats.total}`);
console.log(`   Matched: ${stats.matched} (${Math.round(stats.matched / stats.total * 100)}%)`);
console.log(`   Confidence:`);
console.log(`     - HIGH: ${stats.confidence_high} (${Math.round(stats.confidence_high / stats.total * 100)}%)`);
console.log(`     - MEDIUM: ${stats.confidence_medium} (${Math.round(stats.confidence_medium / stats.total * 100)}%)`);
console.log(`   Review manuelle: ${stats.needs_review} (${Math.round(stats.needs_review / stats.total * 100)}%)`);

return results;

// =====================================================
// 2ND MATCH - ÉQUILIBRÉ (données GOOD)
// =====================================================
// Objectif : Matcher les annonces avec données riches (score 60-80%)
//
// Stratégie :
// - Seuils équilibrés (MIN_COV_ALPHA = 0.80, MIN_ACCEPT = 0.70)
// - Flexibilité href OU field
// - Gates modérés (CC ≤ 150cc, année ±2 ans)
// - Scoring composite avec pénalités
// - 2 passes (avec/sans gate année)
//
// Entrée attendue : Annonces tier "GOOD" (data_quality_score 60-80%)
// Sortie : Annonces matchées avec confiance HIGH majoritaire
// =====================================================

const allItems = $input.all().map(i => i.json);

// =====================================================
// HELPERS GÉNÉRIQUES
// =====================================================

function get(obj, ...keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
}

function pick(obj, keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
}

// =====================================================
// NORMALISATION & TOKENIZATION
// =====================================================

const STOP_WORDS = new Set([
  "moto", "motos", "scooter", "roadster", "trail", "enduro", "cross",
  "vend", "vente", "vends", "urgent", "etat", "tres", "super", "parfait",
  "paiement", "securise", "option", "full", "abs", "a2", "ct", "ok",
  "km", "kms", "kilometrage", "boite", "vitesse", "manuelle",
  "prix", "euro", "eur", "garantie", "factures", "entretien"
]);

function normalize(text) {
  if (!text) return "";
  let s = String(text)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();

  s = s.replace(/_/g, " ");
  s = s.replace(/[/|]/g, " ");
  s = s.replace(/[^a-z0-9]+/g, " ");
  s = s.replace(/\s+/g, " ").trim();

  // Normalisation modèles courants
  s = s.replace(/\b(mt)\s*0?(\d{2})\b/g, "$1$2");
  s = s.replace(/\b(fz)\s*(\d)\b/g, "$1$2");
  s = s.replace(/\b(gs)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(r)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(v\s*strom)\b/g, "vstrom");
  s = s.replace(/\b(dr)\s*z\b/g, "drz");

  return s;
}

function brandKey(brand) {
  return normalize(brand).replace(/\s+/g, "");
}

function tokenize(text) {
  const n = normalize(text);
  if (!n) return [];

  const tokens = n.split(" ").filter(t => {
    if (!t) return false;
    if (STOP_WORDS.has(t)) return false;
    if (/^\d+$/.test(t)) return true;
    return t.length >= 2;
  });

  return tokens;
}

function tokensAlphaOnly(tokens) {
  return tokens.filter(t => /[a-z]/.test(t) && t.length >= 2);
}

function isNumberToken(t) {
  return /^\d+$/.test(t);
}

// =====================================================
// EXTRACTION DONNÉES ANNONCE
// =====================================================

const getAnnonceTitle = (a) =>
  get(a, "text-body-1 (8)", "text-headline-1-expanded", "annonce_title", "relative");

const getAnnonceDesc = (a) =>
  get(a, "annonce_description", "text-body-1 (16)", "text-body-1 (14)", "Description_complete");

const getAnnonceUrl = (a) =>
  get(a, "absolute href", "Url_Https", "annonce_url", "relative");

const getAnnonceBrand = (a) =>
  get(a, "text-body-1 (2)", "annonce_brand_input", "Marque_scrap");

const getAnnonceYearRaw1 = (a) =>
  get(a, "text-body-1 (4)", "Annee_du_modele", "annonce_year_input_1");

const getAnnonceYearRaw2 = (a) =>
  get(a, "text-body-1 (9)", "Mise_en_circulation", "annonce_year_input_2");

const getAnnonceCCHref = (a) => get(a, "text-body-1 href (5)");
const getAnnonceModelHref = (a) => get(a, "text-body-1 href (3)");
const getAnnonceBrandHref = (a) => get(a, "text-body-1 href (2)", "text-body-1 href");

// =====================================================
// EXTRACTION DONNÉES MODÈLE
// =====================================================

const getModeleField = (m) => pick(m, ["Modèle", "Modele", "modele", "Model", "MODELE"]) || "";
const getMarqueField = (m) => pick(m, ["Marque", "marque", "MARQUE", "Brand", "brand"]) || "";
const getYearStartField = (m) => pick(m, ["Année début", "Annee debut", "Year start"]) || "";
const getYearEndField = (m) => pick(m, ["Année fin", "Annee fin", "Year end"]) || "";

// =====================================================
// PARSING ANNÉE
// =====================================================

function parseYearMonth(s) {
  const str = String(s || "").trim();
  if (!str) return { year: 0, month: 0 };

  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return { month: parseInt(mmyyyy[1], 10), year: parseInt(mmyyyy[2], 10) };

  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return { month: 0, year: parseInt(yyyy[0], 10) };

  return { year: 0, month: 0 };
}

function pickAnnonceYear(a, adText) {
  const d1 = parseYearMonth(getAnnonceYearRaw1(a));
  if (d1.year) return d1.year;

  const d2 = parseYearMonth(getAnnonceYearRaw2(a));
  if (d2.year) return d2.year;

  const m = String(adText || "").match(/\b(19|20)\d{2}\b/);
  if (m) return parseInt(m[0], 10);

  return 0;
}

// =====================================================
// EXTRACTION CC
// =====================================================

function ccFromHref(href) {
  const s = String(href || "");
  const m = s.match(/cubic_capacity:(\d{2,4})/i);
  return m ? parseInt(m[1], 10) : 0;
}

function extractCCFromText(text) {
  const raw = String(text || "");
  if (!raw.trim()) return 0;

  const noKm = raw.replace(/\b(\d{1,6})\s*km\b/gi, " ");
  const s = normalize(noKm);

  let m = s.match(/\b(\d{2,4})\s*(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  m = s.match(/\b(\d{2,4})(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  return 0;
}

function extractNumbers(text) {
  const raw = String(text || "")
    .replace(/\b(\d{1,6})\s*km\b/gi, " ")
    .replace(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/g, " ");
  const s = normalize(raw);
  return (s.match(/\b\d{3,4}\b/g) || []).map(n => parseInt(n, 10));
}

function inferCCFromNumbers(adText, annonceYear) {
  const nums = extractNumbers(adText);
  const candidates = nums.filter(n =>
    n >= 50 && n <= 2500 && (!annonceYear || n !== annonceYear)
  );
  if (!candidates.length) return 0;
  return Math.max(...candidates);
}

function getAnnonceCC(a, adText, annonceYear) {
  // Priorité 1 : href
  const ccH = ccFromHref(getAnnonceCCHref(a));
  if (ccH) return ccH;

  // Priorité 2 : champ primary
  const ccTxt = get(a, "text-body-1 (7)", "vehicule_cc_txt", "CC", "cc");
  const ccField = extractCCFromText(ccTxt);
  if (ccField) return ccField;

  // Priorité 3 : champ secondaire
  const ccTxt2 = get(a, "text-body-1 (13)");
  const ccField2 = extractCCFromText(ccTxt2);
  if (ccField2) return ccField2;

  // Priorité 4 : extraction depuis description
  const ccT = extractCCFromText(adText);
  if (ccT) return ccT;

  // Priorité 5 : inférence depuis nombres
  const ccN = inferCCFromNumbers(adText, annonceYear || 0);
  if (ccN) return ccN;

  return 0;
}

// =====================================================
// EXTRACTION BRAND/MODEL DEPUIS HREF
// =====================================================

function decodePlus(s) {
  return String(s || "").replace(/\+/g, " ");
}

function extractBrandFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_brand:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

function extractModelFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_model:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

// =====================================================
// SIMILARITÉ
// =====================================================

function jaccard(aTokens, bTokens) {
  if (!aTokens.length || !bTokens.length) return 0;
  const A = new Set(aTokens);
  const B = new Set(bTokens);
  let inter = 0;
  for (const x of A) if (B.has(x)) inter++;
  const union = A.size + B.size - inter;
  return union ? inter / union : 0;
}

function coverageSet(adSet, modelTokens) {
  if (!modelTokens.length) return 0;
  let hit = 0;
  for (const t of modelTokens) if (adSet.has(t)) hit++;
  return hit / modelTokens.length;
}

// =====================================================
// VARIANTS & DOMINANTS
// =====================================================

function modelVariants(modelRaw) {
  const cleaned = String(modelRaw || "").replace(/[|]/g, "/");
  const parts = cleaned.split("/").map(p => p.trim()).filter(Boolean);
  return Array.from(new Set(parts.map(p => normalize(p)).filter(Boolean)));
}

function getModelDominantTokens(modelRaw) {
  const n = normalize(modelRaw);
  const nums = n.match(/\b\d{3,4}\b/g) || [];
  if (nums.length) return nums.map(Number);

  const toks = tokenize(modelRaw);
  return toks.filter(t => /\d/.test(t) || t.length >= 4);
}

// =====================================================
// SÉPARATION MODÈLES / ANNONCES
// =====================================================

const modeles = [];
const annonces = [];

for (const item of allItems) {
  const isModele =
    !!getMarqueField(item) &&
    !!getModeleField(item) &&
    get(item, "Cylindrée (cc)", "Type (M/S/E)", "Type(M/S/E)") !== "";

  const isAnnonce =
    get(item, "text-body-1 (8)", "text-headline-1-expanded", "relative",
        "absolute href", "Url_Https", "annonce_url") !== "";

  if (isModele) modeles.push(item);
  else if (isAnnonce) annonces.push(item);
}

if (!modeles.length) {
  return annonces.map(a => ({
    json: {
      ...a,
      matching_engine: "2ND_MATCH_NO_MODELS",
      matched_score: 0,
      matched_confidence: "NONE",
      needs_review: true
    }
  }));
}

// =====================================================
// INDEX MARQUES
// =====================================================

const brandIndex = new Map();

for (const m of modeles) {
  const brandRaw = getMarqueField(m);
  const modelRaw = getModeleField(m);

  const bKey = brandKey(brandRaw);
  if (!bKey) continue;

  const variants = modelVariants(modelRaw);
  if (!variants.length) continue;

  const ys = parseInt(getYearStartField(m) || 0, 10) || 0;
  let ye = getYearEndField(m);
  ye = (ye === null || ye === undefined || ye === "") ? 9999 : (parseInt(ye, 10) || 9999);

  const cc = Math.round(Number(get(m, "Cylindrée (cc)") || 0)) || 0;

  const variantAlphaTokens = variants
    .map(v => tokensAlphaOnly(tokenize(v)))
    .filter(t => t.length);

  if (!variantAlphaTokens.length) continue;

  const doms = getModelDominantTokens(modelRaw);
  const modelNoSpace = normalize(modelRaw).replace(/\s+/g, "");

  const prepared = {
    raw: m,
    brandRaw,
    bKey,
    ys,
    ye,
    cc,
    variants,
    variantAlphaTokens,
    combinedTok: tokenize(`${brandRaw} ${modelRaw}`),
    dominants: doms,
    modelNoSpace
  };

  if (!brandIndex.has(bKey)) brandIndex.set(bKey, []);
  brandIndex.get(bKey).push(prepared);
}

const knownBrandKeys = Array.from(brandIndex.keys()).sort((a, b) => b.length - a.length);

// =====================================================
// PARAMÈTRES 2ND MATCH (ÉQUILIBRÉ)
// =====================================================

const MIN_COV_ALPHA = 0.80;    // 80% couverture alpha
const MIN_ACCEPT = 0.70;        // 70% score minimum
const CC_BLOCK_DIFF = 150;      // 150cc tolérance
const YEAR_TOLERANCE = 2;       // ±2 ans tolérance

// =====================================================
// SCORING COMPOSITE AVEC PÉNALITÉS
// =====================================================

function computeBalancedScore(adTok, adSet, p, annonceCC, annonceYear, adNumbers) {
  // 1. Coverage alpha (65%)
  let bestCov = 0;
  for (const vat of p.variantAlphaTokens) {
    const cov = coverageSet(adSet, vat);
    if (cov > bestCov) bestCov = cov;
  }

  // 2. Jaccard (25%)
  const jac = jaccard(adTok, p.combinedTok);

  // 3. CC proximity (7%)
  let ccProximity = 0;
  if (annonceCC && p.cc) {
    const diff = Math.abs(p.cc - annonceCC);
    if (diff === 0) ccProximity = 1.0;
    else if (diff <= 50) ccProximity = 0.8;
    else if (diff <= 100) ccProximity = 0.5;
    else if (diff <= 150) ccProximity = 0.3;
  } else if (!annonceCC && !p.cc) {
    ccProximity = 0.5; // Neutre si les deux absents
  }

  // 4. Year proximity (3%)
  let yearProximity = 0;
  if (annonceYear && p.ys && p.ye) {
    if (annonceYear >= p.ys && annonceYear <= p.ye) {
      yearProximity = 1.0;
    } else {
      const distStart = Math.abs(annonceYear - p.ys);
      const distEnd = Math.abs(annonceYear - p.ye);
      const minDist = Math.min(distStart, distEnd);
      if (minDist <= 1) yearProximity = 0.8;
      else if (minDist <= 2) yearProximity = 0.5;
    }
  } else if (!annonceYear) {
    yearProximity = 0.5; // Neutre si absent
  }

  // Score composite de base
  const baseScore = (
    bestCov * 0.65 +
    jac * 0.25 +
    ccProximity * 0.07 +
    yearProximity * 0.03
  );

  // Pénalités
  let penalties = 0;

  // Pénalité dominants (si présents mais absents dans annonce)
  if (p.dominants.length > 0) {
    const hasCommonDom = p.dominants.some(d => adNumbers.includes(d));
    if (!hasCommonDom) {
      penalties += 0.10; // -10%
    }
  }

  // Pénalité CC absent
  if (!annonceCC && p.cc) {
    penalties += 0.05; // -5%
  }

  const finalScore = Math.max(0, baseScore - penalties);

  return {
    score: finalScore,
    bestCov,
    jac,
    ccProximity,
    yearProximity,
    penalties
  };
}

// =====================================================
// MATCHING
// =====================================================

const results = [];

for (const a of annonces) {
  const title = getAnnonceTitle(a);
  const desc = getAnnonceDesc(a);
  const url = getAnnonceUrl(a);

  const hrefModel = getAnnonceModelHref(a) || "";
  const hrefCC = getAnnonceCCHref(a) || "";
  const hrefBrand = getAnnonceBrandHref(a) || "";

  // Flexibilité href OU field
  const brandFromHrefRaw = extractBrandFromHref(hrefBrand);
  const brandFromFieldRaw = getAnnonceBrand(a);

  const brandFromHrefKey = brandKey(brandFromHrefRaw);
  const brandFromFieldKey = brandKey(brandFromFieldRaw);

  const adTextBase = `${title} ${desc}`.trim();

  // Marque : href OU field
  let brandAnnonceKey = brandFromHrefKey || brandFromFieldKey;

  // Model hint : href (si ≠ "autre") OU field
  let modelHint = extractModelFromHref(hrefModel);
  const modelNorm = normalize(modelHint);
  const isModelAutre = modelNorm === "autre" || modelNorm.includes(" autre");

  if (!modelHint || isModelAutre) {
    // Fallback sur fields
    modelHint = get(a, "text-body-1 (8)", "text-body-1 (3)");
  }

  const adTextUsed = modelHint ? `${adTextBase} ${modelHint}`.trim() : adTextBase;

  const annonceYear = pickAnnonceYear(a, adTextUsed);
  const annonceCC = getAnnonceCC(a, adTextUsed, annonceYear);

  if (!brandAnnonceKey || !brandIndex.has(brandAnnonceKey)) {
    results.push({
      json: {
        ...a,
        annonce_title: title,
        annonce_url: url,
        annonce_year_resolved: annonceYear || "",
        annonce_cc_resolved: annonceCC || "",

        matched_ok: false,
        matched_marque: "",
        matched_modele: modelHint || "",
        matched_score: 0,
        matched_confidence: "NONE",
        matching_engine: "2ND_MATCH_NO_BRAND",
        needs_review: true,
        reason_no_match: "brand_not_found"
      }
    });
    continue;
  }

  const adTok = tokenize(adTextUsed);
  const adSet = new Set(adTok);
  const adNumbers = extractNumbers(adTextUsed);

  const baseCandidates = brandIndex.get(brandAnnonceKey) || [];

  // Passes : avec/sans année
  const passes = [{ useYear: true }, { useYear: false }];

  let bestPrepared = null;
  let bestScore = 0;
  let bestDetails = null;
  let usedYearFilter = false;

  for (const pass of passes) {
    let foundInPass = false;

    for (const p of baseCandidates) {
      // Gate année avec tolérance ±2 ans
      if (pass.useYear && annonceYear) {
        const inRange = annonceYear >= p.ys && annonceYear <= p.ye;

        if (!inRange) {
          const distStart = Math.abs(annonceYear - p.ys);
          const distEnd = Math.abs(annonceYear - p.ye);
          const minDist = Math.min(distStart, distEnd);

          if (minDist > YEAR_TOLERANCE) {
            continue; // Rejeté si > 2 ans hors range
          }
        }
      }

      // Gate CC (≤ 150cc)
      if (annonceCC && p.cc) {
        const diff = Math.abs(p.cc - annonceCC);
        if (diff > CC_BLOCK_DIFF) continue;
      }

      // Scoring avec pénalités
      const { score, bestCov, jac, ccProximity, yearProximity, penalties } =
        computeBalancedScore(adTok, adSet, p, annonceCC, annonceYear, adNumbers);

      // Gate coverage minimum
      if (bestCov < MIN_COV_ALPHA) continue;

      if (score > bestScore) {
        bestScore = score;
        bestPrepared = p;
        bestDetails = { bestCov, jac, ccProximity, yearProximity, penalties };
        usedYearFilter = pass.useYear && !!annonceYear;
        foundInPass = true;
      }
    }

    if (pass.useYear && foundInPass) break;
  }

  const accept = !!bestPrepared && bestScore >= MIN_ACCEPT;
  const best = accept ? bestPrepared.raw : null;

  // Déterminer la confiance
  let confidence = "NONE";
  if (accept) {
    if (bestScore >= 0.78) confidence = "HIGH";
    else confidence = "MEDIUM";
  }

  results.push({
    json: {
      ...a,
      annonce_title: title,
      annonce_url: url,
      annonce_year_resolved: annonceYear || "",
      used_year_filter: usedYearFilter,
      annonce_cc_resolved: annonceCC || "",

      matched_ok: accept,
      matched_marque: accept ? (getMarqueField(best) || "") : "",
      matched_modele: accept ? (getModeleField(best) || "") : (modelHint || ""),
      matched_generations: accept ? (get(best, "Spéc/Génération", "Spec/Generation") || "") : "",
      matched_coloris: accept ? (get(best, "Coloris commercial") || "") : "",
      matched_annee_debut: accept ? (getYearStartField(best) || "") : "",
      matched_annee_fin: accept ? (getYearEndField(best) || "") : "",
      matched_cylindree: accept ? (get(best, "Cylindrée (cc)") || "") : "",

      matched_score: accept ? Number(bestScore.toFixed(3)) : 0,
      matched_confidence: confidence,
      matched_quality: accept ? "auto_match_2nd" : "no_match",
      matching_engine: "2ND_MATCH_BALANCED_V1",
      needs_review: !accept || confidence === "MEDIUM",
      reason_no_match: accept ? "" : "below_threshold_or_filtered",

      _match_debug: {
        brandKey: brandAnnonceKey,
        modelHint,
        adTokensCount: adTok.length,
        coverageAlpha: accept ? Number(bestDetails.bestCov.toFixed(3)) : 0,
        jaccard: accept ? Number(bestDetails.jac.toFixed(3)) : 0,
        ccProximity: accept ? Number(bestDetails.ccProximity.toFixed(2)) : 0,
        yearProximity: accept ? Number(bestDetails.yearProximity.toFixed(2)) : 0,
        penalties: accept ? Number(bestDetails.penalties.toFixed(2)) : 0,
        minCovAlpha: MIN_COV_ALPHA,
        minAccept: MIN_ACCEPT,
        ccBlockDiff: CC_BLOCK_DIFF
      }
    }
  });
}

// =====================================================
// STATS
// =====================================================

const stats = {
  total: results.length,
  matched: results.filter(r => r.json.matched_ok).length,
  confidence_high: results.filter(r => r.json.matched_confidence === "HIGH").length,
  confidence_medium: results.filter(r => r.json.matched_confidence === "MEDIUM").length,
  needs_review: results.filter(r => r.json.needs_review).length
};

console.log("🥈 2ND MATCH (ÉQUILIBRÉ) - STATS:");
console.log(`   Total items: ${stats.total}`);
console.log(`   Matched: ${stats.matched} (${Math.round(stats.matched / stats.total * 100)}%)`);
console.log(`   Confidence:`);
console.log(`     - HIGH: ${stats.confidence_high} (${Math.round(stats.confidence_high / stats.total * 100)}%)`);
console.log(`     - MEDIUM: ${stats.confidence_medium} (${Math.round(stats.confidence_medium / stats.total * 100)}%)`);
console.log(`   Review manuelle: ${stats.needs_review} (${Math.round(stats.needs_review / stats.total * 100)}%)`);

return results;

// =====================================================
// 3RD MATCH - PERMISSIF (données MEDIUM)
// =====================================================
// Objectif : Matcher les annonces avec données moyennes (score 40-60%)
//
// Stratégie :
// - Seuils permissifs (MIN_COV_ALPHA = 0.50, MIN_ACCEPT = 0.55)
// - Inférence intelligente du modèle depuis description
// - Fuzzy brand matching (Levenshtein distance)
// - Scoring composite (coverage + jaccard + CC + année)
// - Relaxation des gates (dominant, CC)
//
// Entrée attendue : Annonces tier "MEDIUM" (data_quality_score 40-60%)
// Sortie : Annonces matchées avec confiance MEDIUM
// =====================================================

const allItems = $input.all().map(i => i.json);

// =====================================================
// HELPERS GÉNÉRIQUES
// =====================================================

function get(obj, ...keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
}

function pick(obj, keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
}

// =====================================================
// NORMALISATION & TOKENIZATION
// =====================================================

const STOP_WORDS = new Set([
  "moto", "motos", "scooter", "roadster", "trail", "enduro", "cross",
  "vend", "vente", "vends", "urgent", "etat", "tres", "super", "parfait",
  "paiement", "securise", "option", "full", "abs", "a2", "ct", "ok",
  "km", "kms", "kilometrage", "boite", "vitesse", "manuelle",
  "prix", "euro", "eur", "garantie", "factures", "entretien"
]);

function normalize(text) {
  if (!text) return "";
  let s = String(text)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();

  s = s.replace(/_/g, " ");
  s = s.replace(/[/|]/g, " ");
  s = s.replace(/[^a-z0-9]+/g, " ");
  s = s.replace(/\s+/g, " ").trim();

  // Normalisation des modèles courants
  s = s.replace(/\b(mt)\s*0?(\d{2})\b/g, "$1$2");
  s = s.replace(/\b(fz)\s*(\d)\b/g, "$1$2");
  s = s.replace(/\b(gs)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(r)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(v\s*strom)\b/g, "vstrom");
  s = s.replace(/\b(dr)\s*z\b/g, "drz");

  return s;
}

function brandKey(brand) {
  return normalize(brand).replace(/\s+/g, "");
}

function tokenize(text) {
  const n = normalize(text);
  if (!n) return [];

  const tokens = n.split(" ").filter(t => {
    if (!t) return false;
    if (STOP_WORDS.has(t)) return false;
    if (/^\d+$/.test(t)) return true; // garde les nombres
    return t.length >= 2;
  });

  return tokens;
}

function tokensAlphaOnly(tokens) {
  return tokens.filter(t => /[a-z]/.test(t) && t.length >= 2);
}

function isNumberToken(t) {
  return /^\d+$/.test(t);
}

// =====================================================
// EXTRACTION DONNÉES ANNONCE
// =====================================================

const getAnnonceTitle = (a) =>
  get(a, "text-body-1 (8)", "text-headline-1-expanded", "annonce_title", "relative");

const getAnnonceDesc = (a) =>
  get(a, "annonce_description", "text-body-1 (16)", "text-body-1 (14)", "Description_complete");

const getAnnonceUrl = (a) =>
  get(a, "absolute href", "Url_Https", "annonce_url", "relative");

const getAnnonceBrand = (a) =>
  get(a, "text-body-1 (2)", "annonce_brand_input", "Marque_scrap");

const getAnnonceYearRaw1 = (a) =>
  get(a, "text-body-1 (4)", "Annee_du_modele", "annonce_year_input_1");

const getAnnonceYearRaw2 = (a) =>
  get(a, "text-body-1 (9)", "Mise_en_circulation", "annonce_year_input_2");

const getAnnonceCCHref = (a) => get(a, "text-body-1 href (5)");
const getAnnonceModelHref = (a) => get(a, "text-body-1 href (3)");
const getAnnonceBrandHref = (a) => get(a, "text-body-1 href (2)", "text-body-1 href");

// =====================================================
// EXTRACTION DONNÉES MODÈLE
// =====================================================

const getModeleField = (m) => pick(m, ["Modèle", "Modele", "modele", "Model", "MODELE"]) || "";
const getMarqueField = (m) => pick(m, ["Marque", "marque", "MARQUE", "Brand", "brand"]) || "";
const getYearStartField = (m) => pick(m, ["Année début", "Annee debut", "Year start"]) || "";
const getYearEndField = (m) => pick(m, ["Année fin", "Annee fin", "Year end"]) || "";

// =====================================================
// PARSING ANNÉE
// =====================================================

function parseYearMonth(s) {
  const str = String(s || "").trim();
  if (!str) return { year: 0, month: 0 };

  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return { month: parseInt(mmyyyy[1], 10), year: parseInt(mmyyyy[2], 10) };

  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return { month: 0, year: parseInt(yyyy[0], 10) };

  return { year: 0, month: 0 };
}

function pickAnnonceYear(a, adText) {
  const d1 = parseYearMonth(getAnnonceYearRaw1(a));
  if (d1.year) return d1.year;

  const d2 = parseYearMonth(getAnnonceYearRaw2(a));
  if (d2.year) return d2.year;

  // Fallback : extraction depuis texte
  const m = String(adText || "").match(/\b(19|20)\d{2}\b/);
  if (m) return parseInt(m[0], 10);

  return 0;
}

// =====================================================
// EXTRACTION CC
// =====================================================

function ccFromHref(href) {
  const s = String(href || "");
  const m = s.match(/cubic_capacity:(\d{2,4})/i);
  return m ? parseInt(m[1], 10) : 0;
}

function extractCCFromText(text) {
  const raw = String(text || "");
  if (!raw.trim()) return 0;

  const noKm = raw.replace(/\b(\d{1,6})\s*km\b/gi, " ");
  const s = normalize(noKm);

  let m = s.match(/\b(\d{2,4})\s*(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  m = s.match(/\b(\d{2,4})(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  return 0;
}

function extractNumbers(text) {
  const raw = String(text || "")
    .replace(/\b(\d{1,6})\s*km\b/gi, " ")
    .replace(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/g, " ");
  const s = normalize(raw);
  return (s.match(/\b\d{3,4}\b/g) || []).map(n => parseInt(n, 10));
}

function inferCCFromNumbers(adText, annonceYear) {
  const nums = extractNumbers(adText);
  const candidates = nums.filter(n =>
    n >= 50 && n <= 2500 && (!annonceYear || n !== annonceYear)
  );
  if (!candidates.length) return 0;
  return Math.max(...candidates);
}

function getAnnonceCC(a, adText, annonceYear) {
  const ccH = ccFromHref(getAnnonceCCHref(a));
  if (ccH) return ccH;

  const ccTxt = get(a, "text-body-1 (7)", "vehicule_cc_txt", "CC", "cc");
  const ccField = extractCCFromText(ccTxt);
  if (ccField) return ccField;

  const ccT = extractCCFromText(adText);
  if (ccT) return ccT;

  const ccN = inferCCFromNumbers(adText, annonceYear || 0);
  if (ccN) return ccN;

  return 0;
}

// =====================================================
// EXTRACTION BRAND/MODEL DEPUIS HREF
// =====================================================

function decodePlus(s) {
  return String(s || "").replace(/\+/g, " ");
}

function extractBrandFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_brand:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

function extractModelFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_model:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

// =====================================================
// ✨ NOUVEAUTÉ : EXTRACTION MODÈLE DEPUIS DESCRIPTION
// =====================================================

/**
 * Tente d'extraire le modèle depuis la description
 * Patterns courants : "TRIUMPH Speed Triple", "YAMAHA MT-07", etc.
 */
function extractModelFromDescription(desc, brandNorm) {
  if (!desc) return "";

  const descNorm = normalize(desc);
  if (!descNorm) return "";

  // Pattern 1 : Marque + Modèle (ex: "triumph speed triple")
  if (brandNorm) {
    const regex = new RegExp(`\\b${brandNorm}\\s+([a-z0-9]+(?:\\s+[a-z0-9]+){0,2})\\b`, "i");
    const m = descNorm.match(regex);
    if (m && m[1]) {
      const extracted = m[1].trim();
      // Vérifier que ce n'est pas juste un mot générique
      if (extracted.length >= 3 && !STOP_WORDS.has(extracted)) {
        return extracted;
      }
    }
  }

  // Pattern 2 : Modèles connus avec chiffres (ex: "mt07", "r1200gs", "z900")
  const modelPatterns = [
    /\b([a-z]{1,3}\d{2,4}[a-z]*)\b/,  // mt07, r1200gs, z900
    /\b(duke|monster|street|tiger|ninja|versys|tracer|diavel)\s*(\d{2,4})?/i
  ];

  for (const pattern of modelPatterns) {
    const m = descNorm.match(pattern);
    if (m && m[0]) {
      return m[0].trim();
    }
  }

  return "";
}

// =====================================================
// ✨ NOUVEAUTÉ : FUZZY BRAND MATCHING (LEVENSHTEIN)
// =====================================================

/**
 * Distance de Levenshtein entre deux chaînes
 */
function levenshtein(a, b) {
  const matrix = [];

  for (let i = 0; i <= b.length; i++) {
    matrix[i] = [i];
  }

  for (let j = 0; j <= a.length; j++) {
    matrix[0][j] = j;
  }

  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      if (b.charAt(i - 1) === a.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1, // substitution
          matrix[i][j - 1] + 1,     // insertion
          matrix[i - 1][j] + 1      // deletion
        );
      }
    }
  }

  return matrix[b.length][a.length];
}

/**
 * Trouve la marque la plus proche par fuzzy matching
 */
function fuzzyMatchBrand(adText, knownBrandKeys, maxDistance = 2) {
  const adNorm = normalize(adText);
  const adTokens = tokenize(adText);

  for (const token of adTokens) {
    if (token.length < 3) continue; // trop court pour matcher

    for (const brandKey of knownBrandKeys) {
      const dist = levenshtein(token, brandKey);
      if (dist <= maxDistance) {
        return brandKey;
      }
    }
  }

  return null;
}

// =====================================================
// SIMILARITÉ
// =====================================================

function jaccard(aTokens, bTokens) {
  if (!aTokens.length || !bTokens.length) return 0;
  const A = new Set(aTokens);
  const B = new Set(bTokens);
  let inter = 0;
  for (const x of A) if (B.has(x)) inter++;
  const union = A.size + B.size - inter;
  return union ? inter / union : 0;
}

function coverageSet(adSet, modelTokens) {
  if (!modelTokens.length) return 0;
  let hit = 0;
  for (const t of modelTokens) if (adSet.has(t)) hit++;
  return hit / modelTokens.length;
}

// =====================================================
// VARIANTS & DOMINANTS
// =====================================================

function modelVariants(modelRaw) {
  const cleaned = String(modelRaw || "").replace(/[|]/g, "/");
  const parts = cleaned.split("/").map(p => p.trim()).filter(Boolean);
  return Array.from(new Set(parts.map(p => normalize(p)).filter(Boolean)));
}

function getModelDominantTokens(modelRaw) {
  const n = normalize(modelRaw);
  const nums = n.match(/\b\d{3,4}\b/g) || [];
  if (nums.length) return nums.map(Number);

  const toks = tokenize(modelRaw);
  return toks.filter(t => /\d/.test(t) || t.length >= 4);
}

// =====================================================
// SÉPARATION MODÈLES / ANNONCES
// =====================================================

const modeles = [];
const annonces = [];

for (const item of allItems) {
  const isModele =
    !!getMarqueField(item) &&
    !!getModeleField(item) &&
    get(item, "Cylindrée (cc)", "Type (M/S/E)", "Type(M/S/E)") !== "";

  const isAnnonce =
    get(item, "text-body-1 (8)", "text-headline-1-expanded", "relative",
        "absolute href", "Url_Https", "annonce_url") !== "";

  if (isModele) modeles.push(item);
  else if (isAnnonce) annonces.push(item);
}

if (!modeles.length) {
  return annonces.map(a => ({
    json: {
      ...a,
      matching_engine: "3RD_MATCH_NO_MODELS",
      matched_score: 0,
      matched_confidence: "NONE",
      needs_review: true
    }
  }));
}

// =====================================================
// INDEX MARQUES
// =====================================================

const brandIndex = new Map();

for (const m of modeles) {
  const brandRaw = getMarqueField(m);
  const modelRaw = getModeleField(m);

  const bKey = brandKey(brandRaw);
  if (!bKey) continue;

  const variants = modelVariants(modelRaw);
  if (!variants.length) continue;

  const ys = parseInt(getYearStartField(m) || 0, 10) || 0;
  let ye = getYearEndField(m);
  ye = (ye === null || ye === undefined || ye === "") ? 9999 : (parseInt(ye, 10) || 9999);

  const cc = Math.round(Number(get(m, "Cylindrée (cc)") || 0)) || 0;

  const variantAlphaTokens = variants
    .map(v => tokensAlphaOnly(tokenize(v)))
    .filter(t => t.length);

  if (!variantAlphaTokens.length) continue;

  const doms = getModelDominantTokens(modelRaw);
  const modelNoSpace = normalize(modelRaw).replace(/\s+/g, "");

  const prepared = {
    raw: m,
    brandRaw,
    bKey,
    ys,
    ye,
    cc,
    variants,
    variantAlphaTokens,
    combinedTok: tokenize(`${brandRaw} ${modelRaw}`),
    dominants: doms,
    modelNoSpace
  };

  if (!brandIndex.has(bKey)) brandIndex.set(bKey, []);
  brandIndex.get(bKey).push(prepared);
}

const knownBrandKeys = Array.from(brandIndex.keys()).sort((a, b) => b.length - a.length);

// =====================================================
// PARAMÈTRES 3RD MATCH (PERMISSIF)
// =====================================================

const MIN_COV_ALPHA = 0.50;    // 50% couverture alpha (permissif)
const MIN_ACCEPT = 0.55;        // 55% score minimum (permissif)
const CC_BLOCK_DIFF = 150;      // 150cc tolérance
const CC_PENALTY = 0.08;        // Pénalité CC

// =====================================================
// ✨ SCORING COMPOSITE
// =====================================================

/**
 * Calcule un score composite avec pondération
 * Coverage (60%) + Jaccard (20%) + CC proximity (10%) + Year proximity (10%)
 */
function computeCompositeScore(adTok, adSet, p, annonceCC, annonceYear) {
  // 1. Coverage alpha (60%)
  let bestCov = 0;
  for (const vat of p.variantAlphaTokens) {
    const cov = coverageSet(adSet, vat);
    if (cov > bestCov) bestCov = cov;
  }

  // 2. Jaccard (20%)
  const jac = jaccard(adTok, p.combinedTok);

  // 3. CC proximity (10%)
  let ccProximity = 0;
  if (annonceCC && p.cc) {
    const diff = Math.abs(p.cc - annonceCC);
    if (diff === 0) ccProximity = 1.0;
    else if (diff <= 50) ccProximity = 0.8;
    else if (diff <= 100) ccProximity = 0.5;
    else if (diff <= 150) ccProximity = 0.3;
  } else if (!annonceCC && !p.cc) {
    ccProximity = 0.5; // neutral si les deux absents
  }

  // 4. Year proximity (10%)
  let yearProximity = 0;
  if (annonceYear && p.ys && p.ye) {
    if (annonceYear >= p.ys && annonceYear <= p.ye) {
      yearProximity = 1.0;
    } else {
      const distStart = Math.abs(annonceYear - p.ys);
      const distEnd = Math.abs(annonceYear - p.ye);
      const minDist = Math.min(distStart, distEnd);
      if (minDist <= 2) yearProximity = 0.5;
      else if (minDist <= 5) yearProximity = 0.3;
    }
  } else if (!annonceYear) {
    yearProximity = 0.5; // neutral si absent
  }

  // Score composite
  const score = (
    bestCov * 0.60 +
    jac * 0.20 +
    ccProximity * 0.10 +
    yearProximity * 0.10
  );

  return { score, bestCov, jac, ccProximity, yearProximity };
}

// =====================================================
// MATCHING
// =====================================================

const results = [];

for (const a of annonces) {
  const title = getAnnonceTitle(a);
  const desc = getAnnonceDesc(a);
  const url = getAnnonceUrl(a);

  const hrefModel = getAnnonceModelHref(a) || "";
  const hrefCC = getAnnonceCCHref(a) || "";
  const hrefBrand = getAnnonceBrandHref(a) || "";

  const brandFromHrefRaw = extractBrandFromHref(hrefBrand);
  const brandFromFieldRaw = getAnnonceBrand(a);

  const brandFromHrefKey = brandKey(brandFromHrefRaw);
  const brandFromFieldKey = brandKey(brandFromFieldRaw);

  const adTextBase = `${title} ${desc}`.trim();
  const adNormBase = normalize(adTextBase);

  // Marque : priorité href → field → fuzzy match
  let brandAnnonceKey = brandFromHrefKey || brandFromFieldKey;

  if (!brandAnnonceKey) {
    // ✨ FUZZY BRAND MATCHING
    const fuzzyBrand = fuzzyMatchBrand(adTextBase, knownBrandKeys, 2);
    if (fuzzyBrand) {
      brandAnnonceKey = fuzzyBrand;
      console.log(`🔍 Fuzzy matched brand: ${fuzzyBrand} from "${adTextBase.slice(0, 50)}..."`);
    }
  }

  // Model hint depuis href
  let modelHint = extractModelFromHref(hrefModel);
  const modelNorm = normalize(modelHint);
  const isModelAutre = modelNorm === "autre" || modelNorm.includes(" autre");

  if (!modelHint || isModelAutre) {
    // ✨ EXTRACTION MODÈLE DEPUIS DESCRIPTION
    const extractedModel = extractModelFromDescription(desc, brandAnnonceKey);
    if (extractedModel) {
      modelHint = extractedModel;
      console.log(`🔍 Extracted model from description: ${extractedModel}`);
    }
  }

  const adTextUsed = modelHint ? `${adTextBase} ${modelHint}`.trim() : adTextBase;

  const annonceYear = pickAnnonceYear(a, adTextUsed);
  const annonceCC = getAnnonceCC(a, adTextUsed, annonceYear);

  // Vérifier si marque trouvée
  if (!brandAnnonceKey || !brandIndex.has(brandAnnonceKey)) {
    results.push({
      json: {
        ...a,
        annonce_title: title,
        annonce_url: url,
        annonce_year_resolved: annonceYear || "",
        annonce_cc_resolved: annonceCC || "",

        matched_ok: false,
        matched_marque: "",
        matched_modele: modelHint || "",
        matched_score: 0,
        matched_confidence: "NONE",
        matching_engine: "3RD_MATCH_NO_BRAND",
        needs_review: true,
        reason_no_match: "brand_not_found_even_with_fuzzy"
      }
    });
    continue;
  }

  const adTok = tokenize(adTextUsed);
  const adSet = new Set(adTok);
  const adNumbers = extractNumbers(adTextUsed);

  const baseCandidates = brandIndex.get(brandAnnonceKey) || [];

  // Passes : avec/sans année
  const passes = [{ useYear: true }, { useYear: false }];

  let bestPrepared = null;
  let bestScore = 0;
  let bestDetails = null;
  let usedYearFilter = false;

  for (const pass of passes) {
    let foundInPass = false;

    for (const p of baseCandidates) {
      // Filtre année (optionnel en pass 1)
      if (pass.useYear && annonceYear) {
        if (annonceYear < p.ys || annonceYear > p.ye) continue;
      }

      // Gate CC relaxé (150cc)
      if (annonceCC && p.cc) {
        const diff = Math.abs(p.cc - annonceCC);
        if (diff > CC_BLOCK_DIFF) continue;
      }

      // ✨ SCORING COMPOSITE
      const { score, bestCov, jac, ccProximity, yearProximity } =
        computeCompositeScore(adTok, adSet, p, annonceCC, annonceYear);

      // Gate alpha coverage minimum
      if (bestCov < MIN_COV_ALPHA) continue;

      let finalScore = score;

      // Pénalité CC si diff > 50cc
      if (annonceCC && p.cc) {
        const diff = Math.abs(p.cc - annonceCC);
        if (diff > 50) {
          finalScore = Math.max(0, finalScore - CC_PENALTY);
        }
      }

      if (finalScore > bestScore) {
        bestScore = finalScore;
        bestPrepared = p;
        bestDetails = { bestCov, jac, ccProximity, yearProximity };
        usedYearFilter = pass.useYear && !!annonceYear;
        foundInPass = true;
      }
    }

    if (pass.useYear && foundInPass) break;
  }

  const accept = !!bestPrepared && bestScore >= MIN_ACCEPT;
  const best = accept ? bestPrepared.raw : null;

  // Déterminer la confiance
  let confidence = "NONE";
  if (accept) {
    if (bestScore >= 0.70) confidence = "HIGH";
    else if (bestScore >= 0.60) confidence = "MEDIUM";
    else confidence = "LOW";
  }

  results.push({
    json: {
      ...a,
      annonce_title: title,
      annonce_url: url,
      annonce_year_resolved: annonceYear || "",
      used_year_filter: usedYearFilter,
      annonce_cc_resolved: annonceCC || "",

      matched_ok: accept,
      matched_marque: accept ? (getMarqueField(best) || "") : "",
      matched_modele: accept ? (getModeleField(best) || "") : (modelHint || ""),
      matched_generations: accept ? (get(best, "Spéc/Génération", "Spec/Generation") || "") : "",
      matched_coloris: accept ? (get(best, "Coloris commercial") || "") : "",
      matched_annee_debut: accept ? (getYearStartField(best) || "") : "",
      matched_annee_fin: accept ? (getYearEndField(best) || "") : "",
      matched_cylindree: accept ? (get(best, "Cylindrée (cc)") || "") : "",

      matched_score: accept ? Number(bestScore.toFixed(3)) : 0,
      matched_confidence: confidence,
      matched_quality: accept ? "auto_match_3rd" : "no_match",
      matching_engine: "3RD_MATCH_PERMISSIVE_V1",
      needs_review: !accept || confidence === "LOW",
      reason_no_match: accept ? "" : "below_threshold_or_filtered",

      // Détails pour debug
      _match_debug: {
        brandKey: brandAnnonceKey,
        modelHint,
        adTokensCount: adTok.length,
        coverageAlpha: accept ? Number(bestDetails.bestCov.toFixed(3)) : 0,
        jaccard: accept ? Number(bestDetails.jac.toFixed(3)) : 0,
        ccProximity: accept ? Number(bestDetails.ccProximity.toFixed(2)) : 0,
        yearProximity: accept ? Number(bestDetails.yearProximity.toFixed(2)) : 0,
        minCovAlpha: MIN_COV_ALPHA,
        minAccept: MIN_ACCEPT,
        ccBlockDiff: CC_BLOCK_DIFF
      }
    }
  });
}

// =====================================================
// STATS
// =====================================================

const stats = {
  total: results.length,
  matched: results.filter(r => r.json.matched_ok).length,
  confidence_high: results.filter(r => r.json.matched_confidence === "HIGH").length,
  confidence_medium: results.filter(r => r.json.matched_confidence === "MEDIUM").length,
  confidence_low: results.filter(r => r.json.matched_confidence === "LOW").length,
  needs_review: results.filter(r => r.json.needs_review).length
};

console.log("🥉 3RD MATCH (PERMISSIF) - STATS:");
console.log(`   Total items: ${stats.total}`);
console.log(`   Matched: ${stats.matched} (${Math.round(stats.matched / stats.total * 100)}%)`);
console.log(`   Confidence:`);
console.log(`     - HIGH: ${stats.confidence_high}`);
console.log(`     - MEDIUM: ${stats.confidence_medium}`);
console.log(`     - LOW: ${stats.confidence_low}`);
console.log(`   Review manuelle: ${stats.needs_review}`);

return results;

// =====================================================
// 4TH MATCH - TRÈS PERMISSIF (données POOR)
// =====================================================
// Objectif : Matcher les annonces avec données pauvres (score 20-40%)
//
// Stratégie :
// - Seuils très permissifs (MIN_ACCEPT = 0.40)
// - Fuzzy matching agressif (Levenshtein ≤ 2)
// - N-gram similarity pour variantes de modèles
// - Inférences multiples (brand, model, CC, year)
// - Scoring composite avancé avec fuzzy bonus
// - Relaxation maximale des gates
//
// Entrée attendue : Annonces tier "POOR" (data_quality_score 20-40%)
// Sortie : Annonces matchées avec confiance LOW/MEDIUM
// =====================================================

const allItems = $input.all().map(i => i.json);

// =====================================================
// HELPERS GÉNÉRIQUES
// =====================================================

function get(obj, ...keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
}

function pick(obj, keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
}

// =====================================================
// NORMALISATION & TOKENIZATION
// =====================================================

const STOP_WORDS = new Set([
  "moto", "motos", "scooter", "roadster", "trail", "enduro", "cross",
  "vend", "vente", "vends", "urgent", "etat", "tres", "super", "parfait",
  "paiement", "securise", "option", "full", "abs", "a2", "ct", "ok",
  "km", "kms", "boite", "vitesse", "prix", "euro", "eur", "garantie"
]);

function normalize(text) {
  if (!text) return "";
  let s = String(text)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();

  s = s.replace(/_/g, " ");
  s = s.replace(/[/|]/g, " ");
  s = s.replace(/[^a-z0-9]+/g, " ");
  s = s.replace(/\s+/g, " ").trim();

  // Normalisation modèles
  s = s.replace(/\b(mt)\s*0?(\d{2})\b/g, "$1$2");
  s = s.replace(/\b(fz)\s*(\d)\b/g, "$1$2");
  s = s.replace(/\b(r)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(gs)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(v\s*strom)\b/g, "vstrom");
  s = s.replace(/\b(dr)\s*z\b/g, "drz");

  return s;
}

function brandKey(brand) {
  return normalize(brand).replace(/\s+/g, "");
}

function tokenize(text) {
  const n = normalize(text);
  if (!n) return [];

  const tokens = n.split(" ").filter(t => {
    if (!t) return false;
    if (STOP_WORDS.has(t)) return false;
    if (/^\d+$/.test(t)) return true;
    return t.length >= 2;
  });

  return tokens;
}

function tokensAlphaOnly(tokens) {
  return tokens.filter(t => /[a-z]/.test(t) && t.length >= 2);
}

// =====================================================
// ✨ NOUVEAUTÉ : LEVENSHTEIN DISTANCE
// =====================================================

/**
 * Calcule la distance de Levenshtein entre deux chaînes
 */
function levenshtein(a, b) {
  if (!a || !b) return 999;

  const matrix = [];
  for (let i = 0; i <= b.length; i++) {
    matrix[i] = [i];
  }
  for (let j = 0; j <= a.length; j++) {
    matrix[0][j] = j;
  }

  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      if (b.charAt(i - 1) === a.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1, // substitution
          matrix[i][j - 1] + 1,     // insertion
          matrix[i - 1][j] + 1      // deletion
        );
      }
    }
  }

  return matrix[b.length][a.length];
}

/**
 * Fuzzy matching sur les tokens avec Levenshtein
 */
function fuzzyTokenMatch(adTokens, modelTokens, maxDist = 2) {
  let matches = 0;
  const used = new Set();

  for (const adTok of adTokens) {
    if (adTok.length < 2) continue;

    for (let i = 0; i < modelTokens.length; i++) {
      if (used.has(i)) continue;

      const modelTok = modelTokens[i];
      if (modelTok.length < 2) continue;

      const dist = levenshtein(adTok, modelTok);
      if (dist <= maxDist) {
        matches++;
        used.add(i);
        break;
      }
    }
  }

  return modelTokens.length > 0 ? matches / modelTokens.length : 0;
}

// =====================================================
// ✨ NOUVEAUTÉ : N-GRAM SIMILARITY
// =====================================================

/**
 * Crée des n-grams d'une chaîne
 */
function ngrams(text, n = 3) {
  const normalized = normalize(text);
  if (!normalized || normalized.length < n) return [];

  const grams = [];
  for (let i = 0; i <= normalized.length - n; i++) {
    grams.push(normalized.substring(i, i + n));
  }
  return grams;
}

/**
 * Similarité basée sur les n-grams (Jaccard)
 */
function ngramSimilarity(text1, text2, n = 3) {
  const grams1 = new Set(ngrams(text1, n));
  const grams2 = new Set(ngrams(text2, n));

  if (grams1.size === 0 || grams2.size === 0) return 0;

  let intersection = 0;
  for (const g of grams1) {
    if (grams2.has(g)) intersection++;
  }

  const union = grams1.size + grams2.size - intersection;
  return union > 0 ? intersection / union : 0;
}

// =====================================================
// EXTRACTION DONNÉES
// =====================================================

const getAnnonceTitle = (a) =>
  get(a, "text-body-1 (8)", "text-headline-1-expanded", "annonce_title", "relative");

const getAnnonceDesc = (a) =>
  get(a, "annonce_description", "text-body-1 (16)", "text-body-1 (14)", "Description_complete");

const getAnnonceUrl = (a) =>
  get(a, "absolute href", "Url_Https", "annonce_url", "relative");

const getAnnonceBrand = (a) =>
  get(a, "text-body-1 (2)", "annonce_brand_input", "Marque_scrap");

const getAnnonceYearRaw1 = (a) => get(a, "text-body-1 (4)", "Annee_du_modele");
const getAnnonceYearRaw2 = (a) => get(a, "text-body-1 (9)", "Mise_en_circulation");

const getAnnonceCCHref = (a) => get(a, "text-body-1 href (5)");
const getAnnonceModelHref = (a) => get(a, "text-body-1 href (3)");
const getAnnonceBrandHref = (a) => get(a, "text-body-1 href (2)", "text-body-1 href");

// Modèles
const getModeleField = (m) => pick(m, ["Modèle", "Modele", "modele", "Model"]) || "";
const getMarqueField = (m) => pick(m, ["Marque", "marque", "MARQUE", "Brand"]) || "";
const getYearStartField = (m) => pick(m, ["Année début", "Annee debut", "Year start"]) || "";
const getYearEndField = (m) => pick(m, ["Année fin", "Annee fin", "Year end"]) || "";

// =====================================================
// PARSING & EXTRACTION
// =====================================================

function parseYearMonth(s) {
  const str = String(s || "").trim();
  if (!str) return { year: 0, month: 0 };

  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return { month: parseInt(mmyyyy[1], 10), year: parseInt(mmyyyy[2], 10) };

  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return { month: 0, year: parseInt(yyyy[0], 10) };

  return { year: 0, month: 0 };
}

function pickAnnonceYear(a, adText) {
  const d1 = parseYearMonth(getAnnonceYearRaw1(a));
  if (d1.year) return d1.year;

  const d2 = parseYearMonth(getAnnonceYearRaw2(a));
  if (d2.year) return d2.year;

  const m = String(adText || "").match(/\b(19|20)\d{2}\b/);
  if (m) return parseInt(m[0], 10);

  return 0;
}

function ccFromHref(href) {
  const s = String(href || "");
  const m = s.match(/cubic_capacity:(\d{2,4})/i);
  return m ? parseInt(m[1], 10) : 0;
}

function extractCCFromText(text) {
  const raw = String(text || "");
  if (!raw.trim()) return 0;

  const noKm = raw.replace(/\b(\d{1,6})\s*km\b/gi, " ");
  const s = normalize(noKm);

  let m = s.match(/\b(\d{2,4})\s*(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  m = s.match(/\b(\d{2,4})(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  return 0;
}

function extractNumbers(text) {
  const raw = String(text || "")
    .replace(/\b(\d{1,6})\s*km\b/gi, " ")
    .replace(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/g, " ");
  const s = normalize(raw);
  return (s.match(/\b\d{3,4}\b/g) || []).map(n => parseInt(n, 10));
}

function inferCCFromNumbers(adText, annonceYear) {
  const nums = extractNumbers(adText);
  const candidates = nums.filter(n =>
    n >= 50 && n <= 2500 && (!annonceYear || n !== annonceYear)
  );
  if (!candidates.length) return 0;
  return Math.max(...candidates);
}

function getAnnonceCC(a, adText, annonceYear) {
  const ccH = ccFromHref(getAnnonceCCHref(a));
  if (ccH) return ccH;

  const ccTxt = get(a, "text-body-1 (7)", "vehicule_cc_txt", "CC", "cc");
  const ccField = extractCCFromText(ccTxt);
  if (ccField) return ccField;

  const ccT = extractCCFromText(adText);
  if (ccT) return ccT;

  const ccN = inferCCFromNumbers(adText, annonceYear || 0);
  if (ccN) return ccN;

  return 0;
}

// =====================================================
// EXTRACTION BRAND/MODEL
// =====================================================

function decodePlus(s) {
  return String(s || "").replace(/\+/g, " ");
}

function extractBrandFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_brand:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

function extractModelFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_model:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

// ✨ Extraction modèle depuis description (aggressive)
function extractModelFromDescription(desc, brandNorm) {
  if (!desc) return "";

  const descNorm = normalize(desc);
  if (!descNorm) return "";

  // Pattern 1 : Marque + Modèle
  if (brandNorm) {
    const regex = new RegExp(`\\b${brandNorm}\\s+([a-z0-9]+(?:\\s+[a-z0-9]+){0,3})\\b`, "i");
    const m = descNorm.match(regex);
    if (m && m[1]) {
      const extracted = m[1].trim();
      if (extracted.length >= 2 && !STOP_WORDS.has(extracted)) {
        return extracted;
      }
    }
  }

  // Pattern 2 : Modèles avec chiffres
  const modelPatterns = [
    /\b([a-z]{1,4}\d{2,4}[a-z]*)\b/,
    /\b(duke|monster|street|tiger|ninja|versys|tracer|diavel|hypermotard)\s*(\d{2,4})?/i,
    /\b(speed\s+triple|street\s+triple|street\s+twin|thruxton|scrambler)\b/i
  ];

  for (const pattern of modelPatterns) {
    const m = descNorm.match(pattern);
    if (m && m[0]) {
      return m[0].trim();
    }
  }

  return "";
}

// ✨ Fuzzy brand matching (max distance 2)
function fuzzyMatchBrand(adText, knownBrandKeys, maxDistance = 2) {
  const adNorm = normalize(adText);
  const adTokens = tokenize(adText);

  for (const token of adTokens) {
    if (token.length < 3) continue;

    for (const brandKey of knownBrandKeys) {
      const dist = levenshtein(token, brandKey);
      if (dist <= maxDistance) {
        return brandKey;
      }
    }
  }

  return null;
}

// =====================================================
// SIMILARITÉ
// =====================================================

function jaccard(aTokens, bTokens) {
  if (!aTokens.length || !bTokens.length) return 0;
  const A = new Set(aTokens);
  const B = new Set(bTokens);
  let inter = 0;
  for (const x of A) if (B.has(x)) inter++;
  const union = A.size + B.size - inter;
  return union ? inter / union : 0;
}

function coverageSet(adSet, modelTokens) {
  if (!modelTokens.length) return 0;
  let hit = 0;
  for (const t of modelTokens) if (adSet.has(t)) hit++;
  return hit / modelTokens.length;
}

// =====================================================
// VARIANTS
// =====================================================

function modelVariants(modelRaw) {
  const cleaned = String(modelRaw || "").replace(/[|]/g, "/");
  const parts = cleaned.split("/").map(p => p.trim()).filter(Boolean);
  return Array.from(new Set(parts.map(p => normalize(p)).filter(Boolean)));
}

// =====================================================
// SÉPARATION MODÈLES / ANNONCES
// =====================================================

const modeles = [];
const annonces = [];

for (const item of allItems) {
  const isModele =
    !!getMarqueField(item) &&
    !!getModeleField(item) &&
    get(item, "Cylindrée (cc)", "Type (M/S/E)", "Type(M/S/E)") !== "";

  const isAnnonce =
    get(item, "text-body-1 (8)", "text-headline-1-expanded", "relative",
        "absolute href", "Url_Https", "annonce_url") !== "";

  if (isModele) modeles.push(item);
  else if (isAnnonce) annonces.push(item);
}

if (!modeles.length) {
  return annonces.map(a => ({
    json: {
      ...a,
      matching_engine: "4TH_MATCH_NO_MODELS",
      matched_score: 0,
      matched_confidence: "NONE",
      needs_review: true
    }
  }));
}

// =====================================================
// INDEX MARQUES
// =====================================================

const brandIndex = new Map();

for (const m of modeles) {
  const brandRaw = getMarqueField(m);
  const modelRaw = getModeleField(m);

  const bKey = brandKey(brandRaw);
  if (!bKey) continue;

  const variants = modelVariants(modelRaw);
  if (!variants.length) continue;

  const ys = parseInt(getYearStartField(m) || 0, 10) || 0;
  let ye = getYearEndField(m);
  ye = (ye === null || ye === undefined || ye === "") ? 9999 : (parseInt(ye, 10) || 9999);

  const cc = Math.round(Number(get(m, "Cylindrée (cc)") || 0)) || 0;

  const variantAlphaTokens = variants
    .map(v => tokensAlphaOnly(tokenize(v)))
    .filter(t => t.length);

  if (!variantAlphaTokens.length) continue;

  const modelNoSpace = normalize(modelRaw).replace(/\s+/g, "");

  const prepared = {
    raw: m,
    brandRaw,
    bKey,
    ys,
    ye,
    cc,
    variants,
    variantAlphaTokens,
    combinedTok: tokenize(`${brandRaw} ${modelRaw}`),
    modelNoSpace,
    modelRaw
  };

  if (!brandIndex.has(bKey)) brandIndex.set(bKey, []);
  brandIndex.get(bKey).push(prepared);
}

const knownBrandKeys = Array.from(brandIndex.keys()).sort((a, b) => b.length - a.length);

// =====================================================
// PARAMÈTRES 4TH MATCH (TRÈS PERMISSIF)
// =====================================================

const MIN_ACCEPT = 0.40;          // 40% score minimum (très permissif)
const CC_RELAXATION = 250;        // 250cc tolérance maximale
const FUZZY_BONUS = 0.15;         // Bonus si fuzzy match
const NGRAM_BONUS = 0.10;         // Bonus si n-gram match

// =====================================================
// ✨ SCORING COMPOSITE AVANCÉ AVEC FUZZY
// =====================================================

function computeAdvancedScore(adTok, adSet, p, adTextFull, annonceCC, annonceYear) {
  const adAlpha = tokensAlphaOnly(adTok);

  // 1. Coverage classique (30%)
  let bestCov = 0;
  for (const vat of p.variantAlphaTokens) {
    const cov = coverageSet(adSet, vat);
    if (cov > bestCov) bestCov = cov;
  }

  // 2. Jaccard classique (15%)
  const jac = jaccard(adTok, p.combinedTok);

  // 3. ✨ Fuzzy token matching (25%)
  let bestFuzzy = 0;
  for (const vat of p.variantAlphaTokens) {
    const fuzzy = fuzzyTokenMatch(adAlpha, vat, 2);
    if (fuzzy > bestFuzzy) bestFuzzy = fuzzy;
  }

  // 4. ✨ N-gram similarity (15%)
  const ngramSim = ngramSimilarity(adTextFull, p.modelRaw, 3);

  // 5. CC proximity (10%)
  let ccProximity = 0;
  if (annonceCC && p.cc) {
    const diff = Math.abs(p.cc - annonceCC);
    if (diff === 0) ccProximity = 1.0;
    else if (diff <= 50) ccProximity = 0.8;
    else if (diff <= 100) ccProximity = 0.6;
    else if (diff <= 150) ccProximity = 0.4;
    else if (diff <= 250) ccProximity = 0.2;
  } else if (!annonceCC && !p.cc) {
    ccProximity = 0.5;
  }

  // 6. Year proximity (5%)
  let yearProximity = 0;
  if (annonceYear && p.ys && p.ye) {
    if (annonceYear >= p.ys && annonceYear <= p.ye) {
      yearProximity = 1.0;
    } else {
      const distStart = Math.abs(annonceYear - p.ys);
      const distEnd = Math.abs(annonceYear - p.ye);
      const minDist = Math.min(distStart, distEnd);
      if (minDist <= 3) yearProximity = 0.6;
      else if (minDist <= 7) yearProximity = 0.3;
    }
  } else if (!annonceYear) {
    yearProximity = 0.5;
  }

  // Score composite
  const baseScore = (
    bestCov * 0.30 +
    jac * 0.15 +
    bestFuzzy * 0.25 +
    ngramSim * 0.15 +
    ccProximity * 0.10 +
    yearProximity * 0.05
  );

  // Bonus
  let bonus = 0;
  if (bestFuzzy >= 0.5) bonus += FUZZY_BONUS;
  if (ngramSim >= 0.4) bonus += NGRAM_BONUS;

  const finalScore = Math.min(1.0, baseScore + bonus);

  return {
    score: finalScore,
    bestCov,
    jac,
    bestFuzzy,
    ngramSim,
    ccProximity,
    yearProximity,
    bonusApplied: bonus
  };
}

// =====================================================
// MATCHING
// =====================================================

const results = [];

for (const a of annonces) {
  const title = getAnnonceTitle(a);
  const desc = getAnnonceDesc(a);
  const url = getAnnonceUrl(a);

  const hrefModel = getAnnonceModelHref(a) || "";
  const hrefCC = getAnnonceCCHref(a) || "";
  const hrefBrand = getAnnonceBrandHref(a) || "";

  const brandFromHrefRaw = extractBrandFromHref(hrefBrand);
  const brandFromFieldRaw = getAnnonceBrand(a);

  const brandFromHrefKey = brandKey(brandFromHrefRaw);
  const brandFromFieldKey = brandKey(brandFromFieldRaw);

  const adTextBase = `${title} ${desc}`.trim();
  const adNormBase = normalize(adTextBase);

  // Brand : href → field → fuzzy
  let brandAnnonceKey = brandFromHrefKey || brandFromFieldKey;

  if (!brandAnnonceKey) {
    const fuzzyBrand = fuzzyMatchBrand(adTextBase, knownBrandKeys, 2);
    if (fuzzyBrand) {
      brandAnnonceKey = fuzzyBrand;
      console.log(`🔍 4th Match - Fuzzy brand: ${fuzzyBrand}`);
    }
  }

  // Model hint
  let modelHint = extractModelFromHref(hrefModel);
  const modelNorm = normalize(modelHint);
  const isModelAutre = modelNorm === "autre" || modelNorm.includes(" autre");

  if (!modelHint || isModelAutre) {
    const extractedModel = extractModelFromDescription(desc, brandAnnonceKey);
    if (extractedModel) {
      modelHint = extractedModel;
      console.log(`🔍 4th Match - Extracted model: ${extractedModel}`);
    }
  }

  const adTextUsed = modelHint ? `${adTextBase} ${modelHint}`.trim() : adTextBase;

  const annonceYear = pickAnnonceYear(a, adTextUsed);
  const annonceCC = getAnnonceCC(a, adTextUsed, annonceYear);

  if (!brandAnnonceKey || !brandIndex.has(brandAnnonceKey)) {
    results.push({
      json: {
        ...a,
        annonce_title: title,
        annonce_url: url,
        annonce_year_resolved: annonceYear || "",
        annonce_cc_resolved: annonceCC || "",

        matched_ok: false,
        matched_marque: "",
        matched_modele: modelHint || "",
        matched_score: 0,
        matched_confidence: "NONE",
        matching_engine: "4TH_MATCH_NO_BRAND",
        needs_review: true,
        reason_no_match: "brand_not_found"
      }
    });
    continue;
  }

  const adTok = tokenize(adTextUsed);
  const adSet = new Set(adTok);

  const baseCandidates = brandIndex.get(brandAnnonceKey) || [];

  // Passes : pas de filtre année strict pour 4th Match
  const passes = [{ useYear: false }];

  let bestPrepared = null;
  let bestScore = 0;
  let bestDetails = null;

  for (const pass of passes) {
    for (const p of baseCandidates) {
      // Gate CC ultra-relaxé (250cc)
      if (annonceCC && p.cc) {
        const diff = Math.abs(p.cc - annonceCC);
        if (diff > CC_RELAXATION) continue;
      }

      // ✨ SCORING AVANCÉ
      const details = computeAdvancedScore(
        adTok, adSet, p, adTextUsed, annonceCC, annonceYear
      );

      if (details.score > bestScore) {
        bestScore = details.score;
        bestPrepared = p;
        bestDetails = details;
      }
    }
  }

  const accept = !!bestPrepared && bestScore >= MIN_ACCEPT;
  const best = accept ? bestPrepared.raw : null;

  // Confiance
  let confidence = "NONE";
  if (accept) {
    if (bestScore >= 0.60) confidence = "MEDIUM";
    else confidence = "LOW";
  }

  results.push({
    json: {
      ...a,
      annonce_title: title,
      annonce_url: url,
      annonce_year_resolved: annonceYear || "",
      annonce_cc_resolved: annonceCC || "",

      matched_ok: accept,
      matched_marque: accept ? (getMarqueField(best) || "") : "",
      matched_modele: accept ? (getModeleField(best) || "") : (modelHint || ""),
      matched_generations: accept ? (get(best, "Spéc/Génération", "Spec/Generation") || "") : "",
      matched_coloris: accept ? (get(best, "Coloris commercial") || "") : "",
      matched_annee_debut: accept ? (getYearStartField(best) || "") : "",
      matched_annee_fin: accept ? (getYearEndField(best) || "") : "",
      matched_cylindree: accept ? (get(best, "Cylindrée (cc)") || "") : "",

      matched_score: accept ? Number(bestScore.toFixed(3)) : 0,
      matched_confidence: confidence,
      matched_quality: accept ? "auto_match_4th" : "no_match",
      matching_engine: "4TH_MATCH_FUZZY_AGGRESSIVE_V1",
      needs_review: !accept || confidence === "LOW",
      reason_no_match: accept ? "" : "below_threshold",

      _match_debug: {
        brandKey: brandAnnonceKey,
        modelHint,
        adTokensCount: adTok.length,
        coverage: accept ? Number(bestDetails.bestCov.toFixed(3)) : 0,
        jaccard: accept ? Number(bestDetails.jac.toFixed(3)) : 0,
        fuzzyMatch: accept ? Number(bestDetails.bestFuzzy.toFixed(3)) : 0,
        ngramSim: accept ? Number(bestDetails.ngramSim.toFixed(3)) : 0,
        ccProximity: accept ? Number(bestDetails.ccProximity.toFixed(2)) : 0,
        yearProximity: accept ? Number(bestDetails.yearProximity.toFixed(2)) : 0,
        bonusApplied: accept ? Number(bestDetails.bonusApplied.toFixed(2)) : 0,
        minAccept: MIN_ACCEPT
      }
    }
  });
}

// =====================================================
// STATS
// =====================================================

const stats = {
  total: results.length,
  matched: results.filter(r => r.json.matched_ok).length,
  confidence_medium: results.filter(r => r.json.matched_confidence === "MEDIUM").length,
  confidence_low: results.filter(r => r.json.matched_confidence === "LOW").length,
